const MN=["January","February","March","April","May","June","July","August","September","October","November","December"];
const MA=["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const months = MODEL.months, S = MODEL.s;
const lastHist = (()=>{ let x=0; months.forEach((m,i)=>{ if(m.h===1) x=i; }); return x; })();
const g=(k,i)=> (S[k]&&S[k][i]!=null?S[k][i]:0);
const aum=i=>g("loan",i)+g("sfrVariant",i)+g("sfr",i);
const debt=i=>g("borrowLocal",i)+g("borrowFx",i)+g("sfl",i)+g("secured",i);
const ytd=(k,i)=>{ const y=+months[i].d.split("-")[0]; let s=0; for(let j=i;j>=0;j--){ if(+months[j].d.split("-")[0]===y) s+=g(k,j); else break; } return s; };
const ytdPrev=(k,i)=> i>=12?ytd(k,i-12):null;
const mLong=d=>{ const [y,m]=d.split("-"); return MN[+m-1]+" "+y; };
const mAbbr=d=>{ const [y,m]=d.split("-"); return MA[+m-1]+" "+y; };
const tick =d=>{ const [y,m]=d.split("-"); return MA[+m-1]+" '"+y.slice(2); };
const monthLong=i=> (i>=0&&i<months.length)?mLong(months[i].d):"—";
const monthAbbr=i=> (i>=0&&i<months.length)?mAbbr(months[i].d):"—";

const money=v=>{ const n=v/1e6, a=Math.abs(n); const s=a>=1000?(a/1000).toFixed(2)+"B":a.toFixed(1)+"M"; return (n<0?"($":"$")+s+(n<0?")":""); };
const pct=(v,d=1)=>(v*100).toFixed(d)+"%";
const xx=v=>v.toFixed(2)+"x";
const fmt=(k,v)=>k==="money"?money(v):k==="pct"?pct(v):k==="x"?xx(v):String(v);

