/* ============================ atoms ============================ */
const Eyebrow=({children,style})=> <div className="eyebrow" style={style}>{children}</div>;
function Delta({ kind, cur, prev, tag }){
  if(prev==null||!isFinite(prev)) return <span className="delta muted">— {tag}</span>;
  let txt,up;
  if(kind==="pct"){ const b=(cur-prev)*10000; up=b>=0; txt=(up?"+":"−")+Math.abs(Math.round(b))+" bps"; }
  else if(kind==="x"){ const d=cur-prev; up=d>=0; txt=(up?"+":"−")+Math.abs(d).toFixed(2)+"x"; }
  else { const d=prev!==0?(cur-prev)/Math.abs(prev)*100:0; up=d>=0; txt=(up?"+":"−")+Math.abs(d).toFixed(1)+"%"; }
  return <span className="delta" style={{color:up?T.pos:T.neg}}>{up?"▲":"▼"} {txt} {tag&&<span className="muted">{tag}</span>}</span>;
}
function Spark({ values, w=128, h=40, color=T.green700 }){
  const v=values.filter(x=>x!=null);
  if(v.length<2) return <svg width={w} height={h}/>;
  const min=Math.min(...v), max=Math.max(...v), rng=(max-min)||1;
  const pts=v.map((y,k)=>[ (k/(v.length-1))*(w-2)+1, h-2-((y-min)/rng)*(h-4) ]);
  const d=pts.map((p,k)=>(k?"L":"M")+p[0].toFixed(1)+" "+p[1].toFixed(1)).join(" ");
  const area=d+` L ${pts[pts.length-1][0].toFixed(1)} ${h} L ${pts[0][0].toFixed(1)} ${h} Z`;
  return <svg width={w} height={h} style={{display:"block"}}>
    <path d={area} fill={color} fillOpacity={0.08}/>
    <path d={d} fill="none" stroke={color} strokeWidth={1.8}/>
    <circle cx={pts[pts.length-1][0]} cy={pts[pts.length-1][1]} r={2.4} fill={color}/>
  </svg>;
}

/* ============================ chart expand framework ============================ */
const ExpandCtx = React.createContext(() => {});
const IcoExpand = () => (<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="15 3 21 3 21 9"/><polyline points="9 21 3 21 3 15"/><line x1="21" y1="3" x2="14" y2="10"/><line x1="3" y1="21" x2="10" y2="14"/></svg>);
function ChartFrame({ title, legend, note, height = 196, render, hl }){
  const open = useContext(ExpandCtx);
  return (
    <div className={"card chart"+(hl?" hl":"")}>
      <div className="chart-top"><Eyebrow>{title}</Eyebrow>
        <button className="iconbtn" title="Expand chart" onClick={()=>open({ title, legend, note, render })}><IcoExpand/></button></div>
      {legend||null}
      <ResponsiveContainer width="100%" height={height}>{render()}</ResponsiveContainer>
      {note?<div className="note">{note}</div>:null}
    </div>
  );
}
function ChartModal({ data, onClose }){
  useEffect(()=>{ const h=e=>{ if(e.key==="Escape") onClose(); }; window.addEventListener("keydown",h); return ()=>window.removeEventListener("keydown",h); },[onClose]);
  return (
    <div className="cmodal-wrap" onClick={onClose}>
      <div className="cmodal" onClick={e=>e.stopPropagation()}>
        <div className="cmodal-head"><div className="cmodal-title">{data.title}</div><button className="x" onClick={onClose} aria-label="Close">✕</button></div>
        {data.legend||null}
        <div className="cmodal-chart"><ResponsiveContainer width="100%" height="100%">{data.render()}</ResponsiveContainer></div>
        {data.note?<div className="note">{data.note}</div>:null}
      </div>
    </div>
  );
}

