function SecQuestions({ questions, onRespond, onStatus, onNavigate, onNew, i }){
  const [respFor,setRespFor]=useState(null);
  const [rUser,setRUser]=useState(""); const [rText,setRText]=useState("");
  const [newOpen,setNewOpen]=useState(false); const [nUser,setNUser]=useState(""); const [nText,setNText]=useState("");
  const [query,setQuery]=useState("");
  const idx=buildSearch(i);
  const q=query.trim().toLowerCase();
  const results=q?(()=>{ const toks=q.split(/\s+/).filter(w=>w.length>1);
    const sc=e=>{ const hay=(e.label+" "+e.terms).toLowerCase(); if(hay.includes(q)) return 3; if(e.label.toLowerCase().includes(q)) return 2; return toks.length&&toks.every(t=>hay.includes(t))?1:0; };
    return idx.map(e=>[sc(e),e]).filter(x=>x[0]>0).sort((a,b)=>b[0]-a[0]).slice(0,12).map(x=>x[1]); })():[];
  const groups={}; results.forEach(r=>{ (groups[r.grp]=groups[r.grp]||[]).push(r); });
  const preset=predefinedQuestions(i);
  const list=[...questions].sort((a,b)=>(a.date<b.date?1:-1));
  return <>
    <PageHead title="Questions & Comments" sub="Search · ask predefined questions · institutional discussion board" />

    {/* universal search */}
    <div className="card searchcard">
      <Eyebrow>Search the dashboard</Eyebrow>
      <input className="in search" placeholder="Search a borrower, metric, ratio, account, industry or assignment… (e.g. Mattilda, ROE, Fintech, Variant)" value={query} onChange={e=>setQuery(e.target.value)} autoFocus/>
      {q && (results.length? Object.keys(groups).map(grp=>(
        <div className="res-grp" key={grp}><div className="res-grp-h">{grp}</div>
          {groups[grp].map((r,k)=>(
            <button className="res" key={k} onClick={()=>onNavigate(r.focus)}>
              <span className="res-l">{r.label}</span><span className="res-s">{r.sub}</span>
              <span className="res-go">Go →</span>
            </button>))}
        </div>)) : <div className="res-empty">No matches for “{query}”.</div>)}
    </div>

    {/* predefined / smart navigation */}
    <Eyebrow style={{marginTop:24}}>Quick questions</Eyebrow>
    <div className="chips">
      {preset.map((p,k)=><button className="qchip" key={k} onClick={()=>onNavigate(p.e.focus)}>{p.q}</button>)}
    </div>

    {/* discussion board */}
    <div className="band"><Eyebrow>Discussion board</Eyebrow>
      <button className="q-btn sm" onClick={()=>setNewOpen(o=>!o)}>{newOpen?"Cancel":"New question"}</button></div>
    {newOpen && <div className="card">
      <input className="in" placeholder="Your name" value={nUser} onChange={e=>setNUser(e.target.value)}/>
      <textarea className="in ta" placeholder="Type your question or comment…" value={nText} onChange={e=>setNText(e.target.value)} style={{marginTop:8}}/>
      <div className="modal-foot"><button className="btn" disabled={!nText.trim()} onClick={()=>{ onNew({user:nUser.trim()||"Anonymous",q:nText.trim(),section:"Questions & Comments"}); setNText(""); setNUser(""); setNewOpen(false); }}>Submit</button></div>
    </div>}
    {list.length===0 && <div className="card"><div className="empty">No discussion yet. Use “New question”, or the Questions button on any section.</div></div>}
    {list.map(item=>(
      <div className="card qcard" key={item.id}>
        <div className="qmeta">
          <span className="chip" style={{background:STATUS[item.status],color:STATUS_TX[item.status]}}>{item.status}</span>
          <span className="qsec">{item.section}</span><span className="qdot">·</span><span className="qdate">{item.date}</span>
          <span className="qdot">·</span><span className="quser">{item.user}</span>
          <select className="status-sel" value={item.status} onChange={e=>onStatus(item.id,e.target.value)}>
            {Object.keys(STATUS).map(s=><option key={s} value={s}>{s}</option>)}</select>
        </div>
        <div className="qtext">{item.q}</div>
        {item.responses.length>0 && <div className="responses">{item.responses.map((r,k)=>(
          <div className="resp" key={k}><div className="resp-meta">{r.user} · {r.date}</div><div className="resp-text">{r.text}</div></div>))}</div>}
        {respFor===item.id ? (
          <div className="resp-form">
            <input className="in" placeholder="Your name" value={rUser} onChange={e=>setRUser(e.target.value)}/>
            <textarea className="in ta sm" placeholder="Write a response…" value={rText} onChange={e=>setRText(e.target.value)}/>
            <div className="modal-foot"><button className="btn ghost" onClick={()=>{setRespFor(null);setRText("");}}>Cancel</button>
              <button className="btn" disabled={!rText.trim()} onClick={()=>{ onRespond(item.id,{user:rUser.trim()||"Anonymous",text:rText.trim()}); setRespFor(null); setRText(""); setRUser(""); }}>Post response</button></div>
          </div>
        ) : <button className="link-btn" onClick={()=>setRespFor(item.id)}>+ Add response</button>}
      </div>
    ))}
  </>;
}

/* ============================ portfolio module ============================ */
const wYield=rows=>{ const a=rows.filter(r=>r.yld>0); const t=a.reduce((s,r)=>s+r.bal,0); return t?a.reduce((s,r)=>s+r.bal*r.yld,0)/t:0; };
const aYield=rows=>{ const a=rows.filter(r=>r.yld>0); return a.length?a.reduce((s,r)=>s+r.yld,0)/a.length:0; };
const byKey=(rows,key)=>{ const m={}; rows.forEach(x=>{ m[x[key]]=(m[x[key]]||0)+x.bal; }); return m; };
function StatTile({ label, value }){ return <div className="tile"><Eyebrow>{label}</Eyebrow><div className="tile-v">{value}</div></div>; }
const Flow=({n,t,s})=> <div className="flow"><span className="flow-n">{n}</span><div><div className="flow-t">{t}</div><div className="flow-s">{s}</div></div></div>;

function Top10({ rows, byYield, total, hlBorrower }){
  const sorted=[...rows].sort((a,b)=>byYield?(b.yld-a.yld):(b.bal-a.bal)).slice(0,10);
  const ref=useRef(null);
  useEffect(()=>{ if(ref.current) ref.current.scrollIntoView({behavior:"smooth",block:"center"}); },[hlBorrower]);
  return <div className="card pad0"><div className="grp">{byYield?"Top 10 Borrowers by Yield":"Top 10 Borrowers by Balance"}</div>
    <table className="tbl"><thead><tr><th>Borrower</th><th>Balance</th><th>Yield</th><th>Industry</th><th>%</th></tr></thead>
      <tbody>{sorted.map(r=>{ const on=!byYield&&hlBorrower===r.b;
        return <tr key={r.b} className={on?"hl-row":""} ref={on?ref:null}><td>{r.b}</td><td className="num">${r.bal.toFixed(1)}M</td><td className="num">{r.yld>0?pct(r.yld):"—"}</td><td className="sub">{r.ind}</td><td className="num">{((r.bal/total)*100).toFixed(1)}%</td></tr>;
      })}</tbody>
    </table></div>;
}
function ActivePassive({ rows, hlBorrower }){
  const total=rows.reduce((s,x)=>s+x.bal,0);
  const active=rows.filter(x=>x.st==="Active").sort((a,b)=>b.bal-a.bal);
  const passive=rows.filter(x=>x.st==="Passive").sort((a,b)=>b.bal-a.bal);
  const aT=active.reduce((s,x)=>s+x.bal,0), pT=passive.reduce((s,x)=>s+x.bal,0);
  const bar=(data,color)=>()=> (
      <BarChart data={data} layout="vertical" margin={{top:4,right:46,left:6,bottom:4}}>
        <XAxis type="number" hide/>
        <YAxis type="category" dataKey="b" width={96} tick={{fontSize:11,fill:T.ink700}} tickLine={false} axisLine={false}/>
        <Tooltip cursor={{fill:T.gray100}} content={({active,payload})=>active&&payload&&payload[0]?
          <div className="tip"><div className="tip-v">{payload[0].payload.b}: ${payload[0].value.toFixed(1)}M</div></div>:null}/>
        <Bar dataKey="bal" radius={[0,3,3,0]} barSize={16}>
          {data.map((d,k)=><Cell key={k} fill={hlBorrower&&d.b===hlBorrower?T.charcoal:color}/>)}
          <LabelList dataKey="bal" position="right" formatter={v=>"$"+v.toFixed(1)+"M"} style={{fontSize:10,fill:T.ink500}}/>
        </Bar>
      </BarChart>);
  return <div className="grid2">
    <ChartFrame title={"Active Portfolio · "+pct(aT/total)+" of book"} height={Math.max(120,active.length*34+20)}
      note={"Borrowers paying interest and/or principal · $"+aT.toFixed(1)+"M · "+active.length+" positions"} render={bar(active,T.green700)}/>
    <ChartFrame title={"Passive Portfolio · "+pct(pT/total)+" of book"} height={Math.max(120,passive.length*34+20)}
      note={"Borrowers with no interest or principal paid · $"+pT.toFixed(1)+"M · "+passive.length+" positions"} render={bar(passive,T.ink400)}/>
  </div>;
}
/* ============================ portfolio overview visuals ============================ */
const ASG_COL = { Variant:T.green800, Covalto:T.green300, Unassigned:T.gray300 };
const asgLegend = <div className="legend"><span style={{color:ASG_COL.Variant}}>▮ Variant</span><span style={{color:T.green600}}>▮ Covalto</span><span style={{color:T.ink400}}>▮ Unassigned</span></div>;

function RankBars({ rows, total, hlBorrower, n=12 }){
  const data=[...rows].sort((a,b)=>b.bal-a.bal).slice(0,n).map(r=>({...r, pctv:r.bal/total*100}));
  const ref=useRef(null);
  useEffect(()=>{ if(ref.current) ref.current.scrollIntoView({behavior:"smooth",block:"center"}); },[hlBorrower]);
  const render=()=> (
    <BarChart data={data} layout="vertical" margin={{top:4,right:58,left:8,bottom:4}}>
      <XAxis type="number" hide/>
      <YAxis type="category" dataKey="b" width={120} tick={{fontSize:11,fill:T.ink700}} tickLine={false} axisLine={false}/>
      <Tooltip cursor={{fill:T.gray100}} content={({active,payload})=>active&&payload&&payload[0]?
        <div className="tip"><div className="tip-l">{payload[0].payload.b}</div><div className="tip-v">${payload[0].payload.bal.toFixed(1)}M · {payload[0].payload.pctv.toFixed(1)}% of book</div><div className="tip-v">{payload[0].payload.asg} · {payload[0].payload.ind}</div></div>:null}/>
      <Bar dataKey="bal" radius={[0,3,3,0]} barSize={17}>
        {data.map((d,k)=><Cell key={k} fill={hlBorrower&&d.b===hlBorrower?T.charcoal:(ASG_COL[d.asg]||T.green600)}/>)}
        <LabelList dataKey="bal" position="right" formatter={v=>"$"+v.toFixed(1)+"M"} style={{fontSize:10,fill:T.ink500,fontWeight:600}}/>
      </Bar>
    </BarChart>);
  return <div ref={ref}><ChartFrame title="Largest Borrowers · top exposures" legend={asgLegend} height={Math.max(180,data.length*30+20)} render={render}/></div>;
}

function Pareto({ rows, total }){
  const sorted=[...rows].sort((a,b)=>b.bal-a.bal);
  let run=0; const data=sorted.map((r,k)=>{ run+=r.bal; return {name:k+1, label:r.b, cum:+(run/total*100).toFixed(2), share:+(r.bal/total*100).toFixed(2)}; });
  const top=(k)=>sorted.slice(0,k).reduce((s,r)=>s+r.bal,0)/total;
  const hhi=Math.round(sorted.reduce((s,r)=>s+Math.pow(r.bal/total,2),0)*10000);
  const render=()=> (
    <ComposedChart data={data} margin={{top:10,right:8,left:-6,bottom:0}}>
      <CartesianGrid stroke={T.gray200} vertical={false}/>
      <XAxis dataKey="name" tick={{fontSize:10,fill:T.ink400}} tickLine={false} axisLine={{stroke:T.gray200}} label={{value:"Borrowers ranked by size",position:"insideBottom",offset:-2,fontSize:9.5,fill:T.ink400}}/>
      <YAxis tickFormatter={v=>v+"%"} tick={{fontSize:10,fill:T.ink400}} width={38} tickLine={false} axisLine={false} domain={[0,100]}/>
      <Tooltip content={({active,payload})=>active&&payload&&payload.length?<div className="tip"><div className="tip-l">Top {payload[0].payload.name}: {payload[0].payload.label}</div><div className="tip-v">Cumulative: {payload[0].payload.cum.toFixed(1)}% of book</div></div>:null}/>
      <ReferenceLine y={80} stroke={T.gray300} strokeDasharray="4 4" label={{value:"80%",position:"right",fontSize:9,fill:T.ink400}}/>
      <Area type="monotone" dataKey="cum" stroke={T.green800} strokeWidth={2.4} fill={T.green800} fillOpacity={0.08}/>
    </ComposedChart>);
  return <div>
    <div className="tiles" style={{marginBottom:12}}>
      <StatTile label="Top 1" value={pct(top(1))}/>
      <StatTile label="Top 5" value={pct(top(5))}/>
      <StatTile label="Top 10" value={pct(top(10))}/>
      <StatTile label="HHI Index" value={hhi}/>
    </div>
    <ChartFrame title="Concentration Curve · cumulative share of book" height={220} note="How much of the portfolio the largest borrowers represent. A steeper curve means higher concentration." render={render}/>
  </div>;
}

function HDist({ title, map, color=T.green700, note }){
  const total=Object.values(map).reduce((s,v)=>s+v,0);
  const data=Object.entries(map).map(([name,value])=>({name,value,pctv:total?value/total*100:0})).sort((a,b)=>b.value-a.value);
  const render=()=> (
    <BarChart data={data} layout="vertical" margin={{top:4,right:64,left:8,bottom:4}}>
      <XAxis type="number" hide/>
      <YAxis type="category" dataKey="name" width={120} tick={{fontSize:11,fill:T.ink700}} tickLine={false} axisLine={false}/>
      <Tooltip cursor={{fill:T.gray100}} content={({active,payload})=>active&&payload&&payload[0]?<div className="tip"><div className="tip-v">{payload[0].payload.name}: ${payload[0].payload.value.toFixed(1)}M · {payload[0].payload.pctv.toFixed(1)}%</div></div>:null}/>
      <Bar dataKey="value" radius={[0,3,3,0]} barSize={16}>
        {data.map((d,k)=><Cell key={k} fill={SERIES[k%SERIES.length]}/>)}
        <LabelList dataKey="pctv" position="right" formatter={v=>v.toFixed(0)+"%"} style={{fontSize:10,fill:T.ink500,fontWeight:600}}/>
      </Bar>
    </BarChart>);
  return <ChartFrame title={title} height={Math.max(160,data.length*30+20)} note={note} render={render}/>;
}

function YieldHist({ rows }){
  const ys=rows.filter(r=>r.yld>0).map(r=>r.yld);
  const lo=ys.length?Math.floor(Math.min.apply(null,ys)/0.005)*0.005:0.15;
  const hi=ys.length?Math.ceil(Math.max.apply(null,ys)/0.005)*0.005:0.30;
  const buckets=[]; for(let x=lo;x<hi-1e-9;x=+(x+0.005).toFixed(5)) buckets.push([x,+(x+0.005).toFixed(5)]);
  const data=buckets.map(([a,b])=>{ const g2=rows.filter(r=>r.yld>=a&&r.yld<b); return {name:(a*100).toFixed(1)+"–"+(b*100).toFixed(1)+"%", bal:+g2.reduce((s,r)=>s+r.bal,0).toFixed(2), count:g2.length}; });
  const render=()=> (
    <BarChart data={data} margin={{top:18,right:8,left:-8,bottom:8}}>
      <CartesianGrid stroke={T.gray200} vertical={false}/>
      <XAxis dataKey="name" tick={{fontSize:8.5,fill:T.ink500}} interval={0} angle={-45} textAnchor="end" height={58} tickLine={false} axisLine={{stroke:T.gray200}}/>
      <YAxis tick={{fontSize:10,fill:T.ink400}} width={36} tickLine={false} axisLine={false} tickFormatter={v=>"$"+v}/>
      <Tooltip cursor={{fill:T.gray100}} content={({active,payload})=>active&&payload&&payload[0]?<div className="tip"><div className="tip-l">{payload[0].payload.name}</div><div className="tip-v">${payload[0].payload.bal.toFixed(1)}M · {payload[0].payload.count} borrowers</div></div>:null}/>
      <Bar dataKey="bal" fill={T.green700} radius={[2,2,0,0]} barSize={18}/>
    </BarChart>);
  return <ChartFrame title="Yield Distribution · balance by 0.50% band" height={240} note="Each bar is a 50 bps yield band. Expand for the full distribution." render={render}/>;
}
function RoLPHistory({ i, rows, from, title }){
  const empty = Array.isArray(rows) && rows.length===0;
  const f0 = from!=null?from:Math.max(0,i-11);
  const data=[]; for(let j=f0;j<=i;j++) data.push({ name:tick(months[j].d), v: empty?0:g("rolpA",j) });
  const cur = empty?0:g("rolpA",i);
  const render=()=> (
    <ComposedChart data={data} margin={{top:12,right:6,left:-8,bottom:0}}>
      <CartesianGrid stroke={T.gray200} vertical={false}/>
      <XAxis dataKey="name" tick={{fontSize:10,fill:T.ink400}} interval="preserveStartEnd" tickLine={false} axisLine={{stroke:T.gray200}}/>
      <YAxis tickFormatter={v=>(v*100).toFixed(0)+"%"} tick={{fontSize:10,fill:T.ink400}} width={44} tickLine={false} axisLine={false} domain={empty?[0,1]:["auto","auto"]}/>
      <Tooltip content={<Tip kind="pct"/>}/>
      <Area type="monotone" dataKey="v" stroke={T.green800} strokeWidth={2.2} fill={T.green800} fillOpacity={0.08}/>
    </ComposedChart>);
  return <ChartFrame title={(title||"Return on Loan Portfolio (annualized)")+" · "+fmt("pct",cur)} height={220}
    note={empty?"No positions in this portfolio — shown explicitly as 0.0%.":"Annualized return on the loan book, monthly."} render={render}/>;
}

function YieldScatter({ rows, hlBorrower }){
  const data=rows.filter(r=>r.yld>0).map(r=>({x:+(r.yld*100).toFixed(2), y:+r.bal.toFixed(2), b:r.b, asg:r.asg}));
  const render=()=> (
    <ScatterChart margin={{top:12,right:12,left:-2,bottom:8}}>
      <CartesianGrid stroke={T.gray200}/>
      <XAxis type="number" dataKey="x" name="Yield" unit="%" tick={{fontSize:10,fill:T.ink400}} tickLine={false} axisLine={{stroke:T.gray200}} domain={["dataMin-1","dataMax+1"]} label={{value:"Yield",position:"insideBottom",offset:-2,fontSize:9.5,fill:T.ink400}}/>
      <YAxis type="number" dataKey="y" name="Balance" unit="M" tick={{fontSize:10,fill:T.ink400}} width={40} tickLine={false} axisLine={false} tickFormatter={v=>"$"+v}/>
      <ZAxis type="number" dataKey="y" range={[40,420]}/>
      <Tooltip cursor={{strokeDasharray:"3 3"}} content={({active,payload})=>active&&payload&&payload[0]?<div className="tip"><div className="tip-l">{payload[0].payload.b}</div><div className="tip-v">${payload[0].payload.y.toFixed(1)}M · {payload[0].payload.x.toFixed(1)}% yield</div><div className="tip-v">{payload[0].payload.asg}</div></div>:null}/>
      <Scatter data={data}>{data.map((d,k)=><Cell key={k} fill={hlBorrower&&d.b===hlBorrower?T.charcoal:(ASG_COL[d.asg]||T.green600)} fillOpacity={0.78}/>)}</Scatter>
    </ScatterChart>);
  return <ChartFrame title="Balance vs Yield · each bubble a borrower" legend={asgLegend} height={230} note="Bubble size scales with balance. Upper-right = large, high-yielding positions." render={render}/>;
}

function PortfolioOverview({ rows, i, hlBorrower }){
  const total=rows.reduce((s,x)=>s+x.bal,0);
  const top=[...rows].sort((a,b)=>b.bal-a.bal);
  const top10=top.slice(0,10).reduce((s,x)=>s+x.bal,0)/total, top1=top[0]?top[0].bal/total:0;
  const treedata=top.map(x=>({name:x.b, size:+x.bal.toFixed(2), fill:ASG_COL[x.asg]||T.green600}));
  return <>
    {/* 01 — Portfolio Size */}
    <div className="hero">
      <div className="hero-cell"><div className="hero-label">Total Portfolio</div><div className="hero-val">${total.toFixed(0)}M</div><div className="hero-delta"><span className="muted2">{rows.length} active positions</span></div></div>
      <div className="hero-cell"><div className="hero-label">Weighted Yield</div><div className="hero-val">{pct(wYield(rows))}</div><div className="hero-delta"><span className="muted2">avg {pct(aYield(rows))}</span></div></div>
      <div className="hero-cell"><div className="hero-label">Average Ticket</div><div className="hero-val">${(total/rows.length).toFixed(1)}M</div><div className="hero-delta"><span className="muted2">largest {pct(top1)} of book</span></div></div>
      <div className="hero-cell"><div className="hero-label">Top-10 Concentration</div><div className="hero-val">{pct(top10)}</div><div className="hero-delta"><span className="muted2">of total balance</span></div></div>
    </div>

    {/* 02 — Composition */}
    <Flow n="01" t="Portfolio Composition" s="Every position, sized by balance and coloured by assignment."/>
    <ChartFrame title="Portfolio Map · all positions" legend={asgLegend} height={300}
      note="Each tile is a borrower. Larger tile = larger balance. Colour shows Variant / Covalto / Unassigned."
      render={()=> <Treemap data={treedata} dataKey="size" content={<TreeCell/>} isAnimationActive={false}/>}/>

    {/* 03 — Largest Borrowers */}
    <Flow n="02" t="Largest Borrowers" s="The names driving the book, ranked by exposure."/>
    <RankBars rows={rows} total={total} hlBorrower={hlBorrower}/>

    {/* 04 — Concentration */}
    <Flow n="03" t="Concentration Analysis" s="How exposure is distributed across the book."/>
    <Pareto rows={rows} total={total}/>

    {/* 05 — Industry */}
    <Flow n="04" t="Industry Exposure" s="Sector composition of the loan book."/>
    <div className="grid2"><HDist title="By Industry ($M)" map={byKey(rows,"ind")} note="Balance and share by sector."/><Donut title="By Facility Type" map={byKey(rows,"type")} note="Share of book by structure."/></div>

    {/* 06 — Currency */}
    <Flow n="05" t="Currency Exposure" s="FX composition of the portfolio."/>
    <div className="grid2"><Donut title="By Currency" map={byKey(rows,"cur")} note="MXN vs USD share of balance."/><HDist title="Currency ($M)" map={byKey(rows,"cur")} note="Absolute balance by currency."/></div>

    {/* 07 — Assignment */}
    <Flow n="06" t="Assignment Exposure" s="How the book is split across funding partners."/>
    <div className="grid2"><Donut title="By Assignment" map={byKey(rows,"asg")} note="Variant, Covalto, Unassigned."/><HDist title="Assignment ($M)" map={byKey(rows,"asg")} note="Absolute balance by assignment."/></div>

    {/* 08 — Yield */}
    <Flow n="07" t="Yield Analysis" s="Distribution of yield across the book."/>
    <div className="grid2"><YieldHist rows={rows}/><YieldScatter rows={rows} hlBorrower={hlBorrower}/></div>

    {/* 09 — Active vs Passive */}
    <Flow n="08" t="Active vs Passive" s="Performing vs non-accruing exposure."/>
    <ActivePassive rows={rows} hlBorrower={hlBorrower}/>

    <Flow n="09" t="Return on Loan Portfolio" s="Annualized book return — full history from January 2025."/>
    <RoLPHistory i={i} rows={null} from={0}/>
  </>;
}

function PortfolioFlow({ rows, facility, i, hlBorrower }){
  const total=rows.reduce((s,x)=>s+x.bal,0);
  const empty=rows.length===0;
  const top=[...rows].sort((a,b)=>b.bal-a.bal);
  const top10=total?top.slice(0,10).reduce((s,x)=>s+x.bal,0)/total:0, top1=total?(top[0]?top[0].bal/total:0):0;
  if(empty) return <>
    <div className="tiles">
      <StatTile label="Total Balance" value="$0.0M"/>
      <StatTile label="Borrowers" value="0"/>
      <StatTile label="Weighted Yield" value="0.0%"/>
      <StatTile label="Return on Loan Portfolio" value="0.0%"/>
    </div>
    <div className="card"><div className="empty">No positions are currently assigned to this portfolio. All metrics are shown as 0.0% — no values are inherited from the overall book or other portfolios.</div></div>
    <Flow n="01" t="Return on Loan Portfolio" s="No positions — explicitly 0.0%."/>
    <RoLPHistory i={i} rows={rows} from={Math.max(0,i-11)}/>
  </>;
  return <>
    <div className="tiles">
      <StatTile label="Total Balance" value={"$"+total.toFixed(1)+"M"}/>
      <StatTile label="Borrowers" value={rows.length}/>
      <StatTile label="Weighted Yield" value={pct(wYield(rows))}/>
      <StatTile label="Average Yield" value={pct(aYield(rows))}/>
      <StatTile label="Average Ticket" value={"$"+(total/rows.length).toFixed(1)+"M"}/>
      <StatTile label="Top-10 Concentration" value={pct(top10)}/>
      {facility&&<StatTile label="Facility" value={"$"+facility+"M"}/>}
      {facility&&<StatTile label="Utilization" value={pct(total/facility)}/>}
    </div>
    <Flow n="01" t="Largest Exposures" s="Where the balance is concentrated."/>
    <div className="grid2"><Top10 rows={rows} total={total} hlBorrower={hlBorrower}/>
      <ChartFrame title="Position Concentration" height={210} note={"Largest single borrower is "+pct(top1)+" of the book."}
        render={()=> <Treemap data={top.map(x=>({name:x.b,size:x.bal}))} dataKey="size" content={<TreeCell/>} isAnimationActive={false}/>}/>
    </div>
    <Flow n="02" t="Industry Exposure" s="Sector composition of the book."/>
    <div className="grid2"><Donut title="By Industry" map={byKey(rows,"ind")}/><Donut title="By Facility Type" map={byKey(rows,"type")}/></div>
    <Flow n="03" t="Currency & Assignment" s="Currency mix and assignment split."/>
    <div className="grid2"><Donut title="By Currency" map={byKey(rows,"cur")}/><Donut title="By Assignment" map={byKey(rows,"asg")}/></div>
    <Flow n="04" t="Active vs Passive" s="Borrower-level comparison, sorted by balance."/>
    <ActivePassive rows={rows} hlBorrower={hlBorrower}/>
    <Flow n="05" t="Return on Loan Portfolio" s="Annualized book return, last 12 months."/>
    <RoLPHistory i={i} rows={rows} from={Math.max(0,i-11)}/>
  </>;
}

/* ============================ sections ============================ */
function OrigByBorrowerChart({ height=300 }){
  const O=ORIGINATION; const borrowers=(O.borrowers||[]).map(x=>x.b);
  const PAL=["#0d473d","#115a4d","#1a6f5f","#2f8e79","#6fbfa6","#b0ebc2","#8c8c8c","#cfcfcf","#3a3a3a","#5c5c5c"];
  const colorOf={}; borrowers.forEach((b,k)=>colorOf[b]=PAL[k%PAL.length]);
  const data=(O.rows||[]).map(r=>({ name:tick(r.m), total:+r.total.toFixed(2), ...Object.fromEntries(borrowers.map(b=>[b,+((r.b&&r.b[b])||0).toFixed(3)])) }));
  const legend=<div className="legend wrap">{borrowers.map(b=><span key={b} style={{color:colorOf[b]}}>▮ {b}</span>)}</div>;
  const tipB=({active,payload,label})=>{ if(!active||!payload||!payload.length) return null;
    const tot=payload[0].payload.total||0; const items=payload.filter(p=>p.value>0).sort((x,y)=>y.value-x.value);
    return <div className="tip"><div className="tip-l">{label} · total ${tot.toFixed(1)}M</div>
      {items.map((p,k)=><div key={k} className="tip-v"><span style={{color:p.fill}}>●</span> {p.name}: ${(+p.value).toFixed(1)}M</div>)}</div>; };
  return <ChartFrame title="Expected Originations by Borrower ($M)" legend={legend} height={height} render={()=> (
    <ComposedChart data={data} margin={{top:20,right:8,left:-6,bottom:0}}>
      <CartesianGrid stroke={T.gray200} vertical={false}/>
      <XAxis dataKey="name" tick={{fontSize:9.5,fill:T.ink400}} interval={0} angle={-30} textAnchor="end" height={48} tickLine={false} axisLine={{stroke:T.gray200}}/>
      <YAxis tick={{fontSize:10,fill:T.ink400}} width={38} tickLine={false} axisLine={false} tickFormatter={v=>"$"+v}/>
      <Tooltip cursor={{fill:T.gray100}} content={tipB}/>
      {borrowers.map((b,k)=><Bar key={b} dataKey={b} stackId="o" fill={colorOf[b]} barSize={18} radius={k===borrowers.length-1?[2,2,0,0]:[0,0,0,0]}/>)}
      <Line dataKey="total" stroke="transparent" dot={false} isAnimationActive={false}>
        <LabelList dataKey="total" position="top" formatter={v=>v>0?"$"+v.toFixed(0):""} style={{fontSize:9,fill:T.charcoal,fontWeight:600}}/>
      </Line>
    </ComposedChart>)}/>;
}

function SecExecutive({ i, onQ, focus, onClearFocus , nav }){
  const hlRef=useRef(null);
  const hlKey = focus&&focus.section==="executive"&&focus.hl&&focus.hl.type==="metric"?focus.hl.key:null;
  useEffect(()=>{ if(hlRef.current) hlRef.current.scrollIntoView({behavior:"smooth",block:"center"}); },[focus]);
  const assets=[
    {label:"Loan Portfolio",color:T.green800,get:x=>g("loan",x)},
    {label:"Cash",color:T.green300,get:x=>g("cash",x)},
    {label:"Other assets",color:T.gray300,get:x=>Math.max(0,g("ta",x)-g("loan",x)-g("cash",x))},
  ];
  return <>
    <PageHead title="Executive Summary" sub={"As of "+monthLong(i)+" · all figures in MXN"} section="Executive Summary" onQ={onQ} nav={nav} i={i}/>
    {focus&&focus.section==="executive"&&<AnswerCard answer={focus.answer} onClear={onClearFocus}/>}

    <HeroKPIs i={i}/>

    <Eyebrow style={{marginTop:24}}>Growth · history &amp; forecast</Eyebrow>
    <div className="grid2">
      <AreaTrend title="AUM · evolution + forecast" fn={x=>aum(x)} kind="money" from={0} to={Math.min(months.length-1,i+12)} forward/>
      <AreaTrend title="Loan Portfolio · evolution + 12-mo forecast" fn={x=>g("loan",x)} kind="money" from={0} to={Math.min(months.length-1,i+12)} forward/>
    </div>

    <Eyebrow style={{marginTop:24}}>Profitability &amp; leverage · history &amp; forecast</Eyebrow>
    <div className="grid2">
      <DualTrend title="Return on Loan Portfolio vs Cost of Financing · +3-mo forecast" aFn={x=>g("rolpA",x)} bFn={x=>g("cofA",x)} aL="Return on book" bL="Cost of financing" kind="pct" from={0} to={Math.min(months.length-1,i+3)} forward/>
      <AreaTrend title="Debt / Equity · evolution" fn={x=>g("de",x)} kind="x" from={0} to={i} color={T.green700}/>
    </div>

    <Eyebrow style={{marginTop:24}}>Expected originations by borrower · Sheet 3</Eyebrow>
    <OrigByBorrowerChart/>

    <Eyebrow style={{marginTop:24}}>Profitability · {monthAbbr(i)} with 12-month trend</Eyebrow>
    <div className="tcards">
      <TrendCard label="ROE (ann.)" kind="pct" fn={x=>g("roeA",x)} i={i}/>
      <TrendCard label="ROA (ann.)" kind="pct" fn={x=>g("roaA",x)} i={i}/>
      <TrendCard label="Net Interest Margin (ann.)" kind="pct" fn={x=>g("nimA",x)} i={i}/>
      <TrendCard label="Return on Loan Portfolio (ann.)" kind="pct" fn={x=>g("rolpA",x)} i={i}/>
    </div>

    <Eyebrow style={{marginTop:24}}>All key indicators · {monthAbbr(i)}<span className="hint"> · vs {monthAbbr(i-1)} and vs {monthAbbr(i-12)} (prior-year YTD)</span></Eyebrow>
    <div className="kpi-grid">{KPIS.map(k=>{
      const cur=k.get(i), pm=i>0?k.get(i-1):null, py=i>=12?k.get(i-12):null; const on=hlKey===k.k;
      return <div className={"kpi"+(on?" hl":"")} key={k.k} ref={on?hlRef:null}>
        <Eyebrow>{k.label}{k.ann?" · ann.":""}</Eyebrow>
        <div className="kpi-val">{fmt(k.kind,cur)}</div>
        <div className="kpi-deltas">
          <Delta kind={k.kind} cur={cur} prev={pm} tag={"vs "+monthAbbr(i-1)}/>
          <Delta kind={k.kind} cur={cur} prev={py} tag={"vs "+monthAbbr(i-12)+(k.ytd?" YTD":"")}/>
        </div>
        <div className="kpi-ex">{k.ex}</div>
      </div>;
    })}</div>

    <Eyebrow style={{marginTop:24}}>Balance composition</Eyebrow>
    <div className="grid2">
      <StackedComposition title="Asset Composition · last 12 months" i={i} parts={assets} note="Stacked balances in MXN millions."/>
      <Donut title={"Funding Mix · "+monthAbbr(i)} map={{Debt:debt(i),Equity:g("eq",i),"Other liabilities":Math.max(0,g("tl",i)-debt(i))}} note="Share of total funding."/>
    </div>
  </>;
}

function TrendCard({ label, kind, fn, i, from }){
  const open=useContext(ExpandCtx);
  const f0=from!=null?from:Math.max(0,i-11); const vals=[]; for(let j=f0;j<=i;j++) vals.push(fn(j));
  const cur=fn(i), pm=i>0?fn(i-1):null;
  const data=[]; for(let j=f0;j<=i;j++){ const v=fn(j); data.push({name:tick(months[j].d), hist:(months[j].h===1||j===lastHist)?v:null, fcst:(months[j].h===0||j===lastHist)?v:null}); }
  const render=()=> (
    <ComposedChart data={data} margin={{top:10,right:6,left:-8,bottom:0}}>
      <CartesianGrid stroke={T.gray200} vertical={false}/>
      <XAxis dataKey="name" tick={{fontSize:10,fill:T.ink400}} interval="preserveStartEnd" tickLine={false} axisLine={{stroke:T.gray200}}/>
      <YAxis tickFormatter={axF(kind)} tick={{fontSize:10,fill:T.ink400}} width={44} tickLine={false} axisLine={false}/>
      <Tooltip content={<Tip kind={kind}/>}/>
      <Area type="monotone" dataKey="hist" stroke="none" fill={T.green800} fillOpacity={0.06}/>
      <Line type="monotone" dataKey="hist" stroke={T.green800} strokeWidth={2} dot={false} connectNulls/>
      <Line type="monotone" dataKey="fcst" stroke={T.green600} strokeWidth={2} strokeDasharray="5 4" dot={false} connectNulls/>
    </ComposedChart>);
  return <div className="card tcard clickable" onClick={()=>open({title:label, render})} title="Expand chart">
    <div className="tcard-top"><Eyebrow>{label}</Eyebrow><span className="iconbtn xs"><IcoExpand/></span></div>
    <div className="tcard-row"><div className="tcard-val">{fmt(kind,cur)}</div><Spark values={vals}/></div>
    <Delta kind={kind} cur={cur} prev={pm} tag={"vs "+monthAbbr(i-1)}/>
  </div>;
}

function DetailStatement({ title, lines, i, initialQuery }){
  const [open,setOpen]=useState(true); const [q,setQ]=useState(initialQuery||"");
  useEffect(()=>{ if(initialQuery){ setOpen(true); setQ(initialQuery); } },[initialQuery]);
  const idx=i, pidx=i-1;
  const flt = q.trim().toLowerCase();
  return <div className="card pad0 stmt">
    <button className="stmt-head" onClick={()=>setOpen(o=>!o)}>
      <span className="grp-inline">{title}</span>
      <span className="stmt-toggle">{open?"Collapse ▲":"Expand ▼"}</span>
    </button>
    {open && <>
      <div className="stmt-search"><input className="in sm" placeholder="Search accounts…" value={q} onChange={e=>setQ(e.target.value)}/>
        <span className="stmt-cols">{monthAbbr(idx)} vs {monthAbbr(pidx)}</span></div>
      <table className="tbl stmt-tbl">
        <tbody>{lines.map((ln,k)=>{
          if(flt && ln.lvl!==0 && !ln.n.toLowerCase().includes(flt)) return null;
          if(ln.lvl===0) return <tr key={k} className="lvl-h"><td colSpan={3}>{ln.n}</td></tr>;
          const cur=ln.v[idx]!=null?ln.v[idx]:0, prev=pidx>=0&&ln.v[pidx]!=null?ln.v[pidx]:null;
          const up=prev!=null&&cur>=prev; const chg=prev&&prev!==0?(cur-prev)/Math.abs(prev)*100:null;
          return <tr key={k} className={ln.lvl===2?"lvl-t":"lvl-l"}>
            <td>{ln.n}</td>
            <td className="num">{money(cur)}</td>
            <td className="num chgcol">{chg==null?"—":<span style={{color:up?T.pos:T.neg}}>{up?"▲":"▼"} {(chg>=0?"+":"")+chg.toFixed(1)}%</span>}</td>
          </tr>;
        })}</tbody>
      </table>
    </>}
  </div>;
}

function SecHistorical({ i, onQ, focus, onClearFocus, nav }){
  const [range,setRange]=useState(12);
  const openChart=useContext(ExpandCtx);
  const hlRef=useRef(null);
  const f = focus&&focus.section==="historical"?focus:null;
  const hlRatio = f&&f.hl&&f.hl.type==="ratio"?f.hl.key:null;
  const hlAccount = f&&f.hl&&f.hl.type==="account"?f.hl.key:null;
  useEffect(()=>{ if(hlRef.current) hlRef.current.scrollIntoView({behavior:"smooth",block:"center"}); },[focus]);
  const from=range==="all"?0:Math.max(0,i-(range-1));
  const pm=i-1;
  // waterfall P&L (selected month)
  const TI=g("totInc",i),CF=g("tcf",i),OP=g("opex",i),OPI=g("opInc",i),NONOP=g("nibt",i)-OPI,TAX=g("tax",i),NI=g("ni",i);
  const wf=[
    {name:"Total Income",type:"total",amount:TI,color:T.green800},
    {name:"− Cost of Financing",type:"delta",amount:-CF},
    {name:"− Operating Exp.",type:"delta",amount:-OP},
    {name:(NONOP>=0?"+":"−")+" Other, net",type:"delta",amount:NONOP},
    {name:"− Income Taxes",type:"delta",amount:-TAX},
    {name:"Net Income",type:"total",amount:NI,color:T.green700},
  ];
  // NI bridge MoM
  const d=(k)=>g(k,i)-g(k,pm);
  const bridge=pm>=0?[
    {name:monthAbbr(pm)+" Net Income",type:"total",amount:g("ni",pm),color:T.green800},
    {name:"Δ Income",type:"delta",amount:d("totInc")},
    {name:"Δ Cost of Fin.",type:"delta",amount:-d("tcf")},
    {name:"Δ Operating Exp.",type:"delta",amount:-d("opex")},
    {name:"Δ Other & Tax",type:"delta",amount:(d("nibt")-d("opInc"))-d("tax")},
    {name:monthAbbr(i)+" Net Income",type:"total",amount:g("ni",i),color:T.green700},
  ]:null;
  return <>
    <PageHead title="Historical Financials" sub={"Reporting period · "+monthLong(i)+" · MXN"} section="Historical Financials" onQ={onQ} nav={nav} i={i}/>
    {f&&<AnswerCard answer={f.answer} onClear={onClearFocus}/>}

    <Eyebrow style={{marginTop:4}}>Key metrics · last 12 months to {monthAbbr(i)}</Eyebrow>
    <div className="tcards">
      <TrendCard label="Loan Portfolio" kind="money" fn={x=>g("loan",x)} i={i}/>
      <TrendCard label="Equity" kind="money" fn={x=>g("eq",x)} i={i}/>
      <TrendCard label="Total Debt" kind="money" fn={debt} i={i}/>
      <TrendCard label="Net Income" kind="money" fn={x=>g("ni",x)} i={i}/>
      <TrendCard label="ROE (ann.)" kind="pct" fn={x=>g("roeA",x)} i={i}/>
      <TrendCard label="Net Interest Margin (ann.)" kind="pct" fn={x=>g("nimA",x)} i={i}/>
    </div>

    <Eyebrow style={{marginTop:28}}>How {monthAbbr(i)} earnings were built</Eyebrow>
    <div className="grid2">
      <Waterfall title={"Income → Net Income · "+monthLong(i)} steps={wf} note={"From total income to net income for "+monthLong(i)+"."}/>
      {bridge && <Waterfall title={"Net Income Bridge · "+monthAbbr(pm)+" → "+monthAbbr(i)} steps={bridge} note={"What moved net income versus "+monthLong(pm)+"."}/>}
    </div>

    <Eyebrow style={{marginTop:28}}>Leverage</Eyebrow>
    <DEEvolution i={i} hl={hlRatio==="de"}/>
    <div className="grid2">
      <StackedComposition title="Asset Composition · last 12 months" i={i} parts={[
        {label:"Loan Portfolio",color:T.green800,get:x=>g("loan",x)},
        {label:"Cash",color:T.green300,get:x=>g("cash",x)},
        {label:"Other assets",color:T.gray300,get:x=>Math.max(0,g("ta",x)-g("loan",x)-g("cash",x))},
      ]} note="Stacked balances in MXN millions."/>
      <StackedComposition title="Funding Composition · last 12 months" i={i} parts={[
        {label:"Total Debt",color:T.green800,get:debt},
        {label:"Equity",color:T.green300,get:x=>g("eq",x)},
        {label:"Other liabilities",color:T.gray300,get:x=>Math.max(0,g("tl",x)-debt(x))},
      ]} note="Stacked balances in MXN millions."/>
    </div>

    <Eyebrow style={{marginTop:28}}>Financial health scorecard · {monthAbbr(i)} with 12-month trend</Eyebrow>
    {RATIOS.map(([grp,items])=>(
      <div className="card pad0 score" key={grp}>
        <div className="grp">{grp}</div>
        {items.map(([k,l,kind,ex])=>{ const from2=Math.max(0,i-11); const vals=[]; for(let j=from2;j<=i;j++) vals.push(g(k,j)); const on=hlRatio===k;
          const cdata=[]; for(let j=from2;j<=i;j++) cdata.push({name:tick(months[j].d), v:g(k,j)});
          const crender=()=> (
            <ComposedChart data={cdata} margin={{top:10,right:6,left:-8,bottom:0}}>
              <CartesianGrid stroke={T.gray200} vertical={false}/>
              <XAxis dataKey="name" tick={{fontSize:10,fill:T.ink400}} interval="preserveStartEnd" tickLine={false} axisLine={{stroke:T.gray200}}/>
              <YAxis tickFormatter={axF(kind)} tick={{fontSize:10,fill:T.ink400}} width={46} tickLine={false} axisLine={false}/>
              <Tooltip content={<Tip kind={kind}/>}/>
              <Area type="monotone" dataKey="v" stroke={T.green800} strokeWidth={2} fill={T.green800} fillOpacity={0.07}/>
            </ComposedChart>);
          return <div className={"score-row clickable"+(on?" hl":"")} key={k} ref={on?hlRef:null} onClick={()=>openChart({title:l, render:crender})} title="Expand chart">
            <div className="score-name">{l}<div className="sub">{ex}</div></div>
            <div className="score-spark"><Spark values={vals} w={96} h={30}/></div>
            <div className="score-val">{fmt(kind,g(k,i))}</div>
            <div className="score-delta"><Delta kind={kind} cur={g(k,i)} prev={g(k,pm)} tag={"vs "+monthAbbr(pm)}/><Delta kind={kind} cur={g(k,i)} prev={i>=12?g(k,i-12):null} tag={"vs "+monthAbbr(i-12)}/></div>
          </div>;
        })}
      </div>
    ))}

    <div className="band"><Eyebrow>Trends</Eyebrow><Range range={range} setRange={setRange}/></div>
    <div className="grid2">
      <DualTrend title="Return on Loan Portfolio vs Cost of Funds" aFn={x=>g("rolpA",x)} bFn={x=>g("cofA",x)} aL="Return" bL="Cost of funds" kind="pct" from={from} to={i}/>
      <Trend title="Total Income" fn={x=>g("totInc",x)} kind="money" from={from} to={i}/>
      <Trend title="Operating Expenses" fn={x=>g("opex",x)} kind="money" from={from} to={i}/>
      <Trend title="Net Income" fn={x=>g("ni",x)} kind="money" from={from} to={i}/>
      <Trend title="Equity" fn={x=>g("eq",x)} kind="money" from={from} to={i}/>
      <Trend title="Return on Equity (annualized)" fn={x=>g("roeA",x)} kind="pct" from={from} to={i}/>
    </div>

    <Eyebrow style={{marginTop:28}}>Detailed Financial Statements</Eyebrow>
    <div className="note" style={{margin:"0 2px 10px"}}>Full statements with original account names. Arrows compare {monthLong(i)} with {monthLong(pm)}.</div>
    <DetailStatement title="Full Income Statement" lines={MODEL.stmt.income} i={i} initialQuery={hlAccount}/>
    <DetailStatement title="Full Balance Sheet" lines={MODEL.stmt.balance} i={i} initialQuery={hlAccount}/>
  </>;
}

function SecProjections({ i, onQ, nav }){
  const cur=i, m6=Math.min(months.length-1,i+6), m12=Math.min(months.length-1,i+12);
  const from=0, to=m12;
  const v=(k,j)=>k==="__debt"?debt(j):g(k,j);
  const SNAP=[["Loan Portfolio","loan","money"],["Total Assets","ta","money"],["Total Debt","__debt","money"],["Total Equity","eq","money"],["Net Income (mo.)","ni","money"],["Total Income (mo.)","totInc","money"]];
  const HERO=[["Loan Portfolio","loan"],["Total Assets","ta"],["Total Equity","eq"],["Net Income (mo.)","ni"]];
  const growth=(k)=>{ const a=v(k,cur), b=v(k,m12); return a?((b-a)/Math.abs(a)*100):0; };
  return <>
    <PageHead title="Projections" sub={"12-month forecast · "+monthLong(cur)+" → "+monthLong(m12)+" · MXN"} section="Projections" onQ={onQ} nav={nav} i={i}/>

    <div className="hero">
      {HERO.map(([l,k])=>{ const b=v(k,m12), gr=growth(k);
        return <div className="hero-cell" key={k}>
          <div className="hero-label">{l}</div><div className="hero-val">{money(b)}</div>
          <div className="hero-delta"><span className="muted2" style={{color:gr>=0?T.mint300:"#f3b0a8"}}>{(gr>=0?"▲ +":"▼ ")+gr.toFixed(1)+"% by "+monthAbbr(m12)}</span></div>
        </div>; })}
    </div>

    <Eyebrow style={{marginTop:24}}>Projected snapshot · {monthAbbr(cur)} → {monthAbbr(m12)}</Eyebrow>
    <div className="pcards">
      {SNAP.map(([l,k,kind])=>{ const aa=v(k,cur), bb=v(k,m12);
        return <div className="card pcard" key={l}>
          <Eyebrow>{l}</Eyebrow>
          <div className="pcard-row">
            <div className="pcard-col"><div className="pcard-lab">{monthAbbr(cur)}</div><div className="pcard-now">{fmt(kind,aa)}</div></div>
            <div className="pcard-arrow">→</div>
            <div className="pcard-col"><div className="pcard-lab">{monthAbbr(m12)}</div><div className="pcard-proj">{fmt(kind,bb)}</div></div>
          </div>
          <Delta kind={kind} cur={bb} prev={aa} tag="12-mo change"/>
        </div>; })}
    </div>

    <Eyebrow style={{marginTop:24}}>Growth trajectory</Eyebrow>
    <div className="grid2">
      <AreaTrend title="Loan Portfolio" fn={x=>g("loan",x)} kind="money" from={from} to={to} forward/>
      <AreaTrend title="Total Assets" fn={x=>g("ta",x)} kind="money" from={from} to={to} forward/>
    </div>

    <Eyebrow style={{marginTop:24}}>Profitability trajectory</Eyebrow>
    <div className="grid2">
      <DualTrend title="Return on Loan Portfolio vs Cost of Funds" aFn={x=>g("rolpA",x)} bFn={x=>g("cofA",x)} aL="Return" bL="Cost of funds" kind="pct" from={from} to={to} forward/>
      <AreaTrend title="Net Income (monthly)" fn={x=>g("ni",x)} kind="money" from={from} to={to} forward/>
    </div>
    <div className="tcards" style={{marginTop:14}}>
      <TrendCard label="ROE (ann.) · projected" kind="pct" fn={x=>g("roeA",x)} i={m12} from={from}/>
      <TrendCard label="Net Interest Margin (ann.) · projected" kind="pct" fn={x=>g("nimA",x)} i={m12} from={from}/>
      <TrendCard label="Cost of Funds (ann.) · projected" kind="pct" fn={x=>g("cofA",x)} i={m12} from={from}/>
    </div>

    <Eyebrow style={{marginTop:24}}>Balance sheet evolution</Eyebrow>
    <div className="grid2">
      <AreaTrend title="Total Equity" fn={x=>g("eq",x)} kind="money" from={from} to={to} forward/>
      <AreaTrend title="Total Debt" fn={x=>debt(x)} kind="money" from={from} to={to} forward/>
    </div>
    <div className="grid2">
      <DualTrend title="Leverage · Debt-to-Equity & Equity Ratio" aFn={x=>g("de",x)} bFn={x=>g("eqRatio",x)} aL="Debt / Equity (x)" bL="Equity ratio" kind="x" from={from} to={to} forward/>
      <AreaTrend title="Cash & Equivalents" fn={x=>g("cash",x)} kind="money" from={from} to={to} forward/>
    </div>
  </>;
}

function nextMonthLabels(i,n){ const out=[]; let [y,m]=months[i].d.split("-").map(Number);
  for(let k=0;k<n;k++){ m++; if(m>12){m=1;y++;} out.push(MA[m-1]+" "+y); } return out; }
function SecOrigination({ i, onQ, nav }){
  const O = ORIGINATION;
  const borrowers = (O.borrowers||[]).map(x=>x.b);
  const PAL = ["#0d473d","#115a4d","#1a6f5f","#2f8e79","#6fbfa6","#b0ebc2","#8c8c8c","#cfcfcf","#3a3a3a","#5c5c5c"];
  const colorOf = {}; borrowers.forEach((b,k)=>colorOf[b]=PAL[k%PAL.length]);
  const data = (O.rows||[]).map(r=>({ name:tick(r.m), total:+r.total.toFixed(2), ...Object.fromEntries(borrowers.map(b=>[b, +((r.b&&r.b[b])||0).toFixed(3)])) }));
  const grand = (O.borrowers||[]).reduce((s,x)=>s+x.total,0);
  const peak = (O.rows||[]).reduce((p,r)=>r.total>p.total?r:p,{total:0,m:""});
  const active = (O.rows||[]).filter(r=>r.total>0).length;
  const monthly = (O.rows||[]).map(r=>({ name:tick(r.m), total:+r.total.toFixed(1) }));
  const ranking = [...(O.borrowers||[])].map(x=>({ name:x.b, value:x.total })).sort((a,b)=>b.value-a.value);
  const legend = <div className="legend wrap">{borrowers.map(b=><span key={b} style={{color:colorOf[b]}}>▮ {b}</span>)}</div>;
  const tipB = ({active,payload,label}) => { if(!active||!payload||!payload.length) return null;
    const tot=payload[0].payload.total||0;
    const items=payload.filter(p=>p.value>0).sort((x,y)=>y.value-x.value);
    return <div className="tip"><div className="tip-l">{label} · total ${tot.toFixed(1)}M</div>
      {items.map((p,k)=><div key={k} className="tip-v"><span style={{color:p.fill}}>●</span> {p.name}: ${(+p.value).toFixed(1)}M</div>)}</div>; };
  const firstM = O.rows&&O.rows[0]?tick(O.rows[0].m):"";
  const lastM = O.rows&&O.rows.length?tick(O.rows[O.rows.length-1].m):"";
  return <>
    <PageHead title="Draw Forecast" sub={"Expected loan production by borrower · "+firstM+" – "+lastM+" · MXN millions"} section="Draw Forecast" onQ={onQ} nav={nav} i={i}/>
    <div className="badge">Live from Sheet 3 (Portfolio Draws) — updates automatically</div>

    <div className="hero" style={{marginTop:12}}>
      <div className="hero-cell"><div className="hero-label">Total Expected</div><div className="hero-val">${grand.toFixed(0)}M</div><div className="hero-delta"><span className="muted2">{active} months of production</span></div></div>
      <div className="hero-cell"><div className="hero-label">Peak Month</div><div className="hero-val">${peak.total.toFixed(0)}M</div><div className="hero-delta"><span className="muted2">{peak.m?tick(peak.m):"—"}</span></div></div>
      <div className="hero-cell"><div className="hero-label">Avg / Active Month</div><div className="hero-val">${(active?grand/active:0).toFixed(1)}M</div><div className="hero-delta"><span className="muted2">across the pipeline</span></div></div>
      <div className="hero-cell"><div className="hero-label">Borrowers</div><div className="hero-val">{borrowers.length}</div><div className="hero-delta"><span className="muted2">receiving capital</span></div></div>
    </div>

    <Eyebrow style={{marginTop:24}}>Expected Originations by Borrower · where capital is deployed each month</Eyebrow>
    <ChartFrame title="Expected Originations by Borrower ($M)" legend={legend} height={300} render={()=> (
      <ComposedChart data={data} margin={{top:20,right:8,left:-6,bottom:0}}>
        <CartesianGrid stroke={T.gray200} vertical={false}/>
        <XAxis dataKey="name" tick={{fontSize:9.5,fill:T.ink400}} interval={0} angle={-30} textAnchor="end" height={48} tickLine={false} axisLine={{stroke:T.gray200}}/>
        <YAxis tick={{fontSize:10,fill:T.ink400}} width={38} tickLine={false} axisLine={false} tickFormatter={v=>"$"+v}/>
        <Tooltip cursor={{fill:T.gray100}} content={tipB}/>
        {borrowers.map((b,k)=><Bar key={b} dataKey={b} stackId="o" fill={colorOf[b]} barSize={18} radius={k===borrowers.length-1?[2,2,0,0]:[0,0,0,0]}/>)}
        <Line dataKey="total" stroke="transparent" dot={false} isAnimationActive={false}>
          <LabelList dataKey="total" position="top" formatter={v=>v>0?"$"+v.toFixed(0):""} style={{fontSize:9,fill:T.charcoal,fontWeight:600}}/>
        </Line>
      </ComposedChart>)}/>

    <Eyebrow style={{marginTop:24}}>Monthly Origination Forecast · total production per month</Eyebrow>
    <ChartFrame title="Monthly Origination Forecast ($M)" height={230} render={()=> (
      <BarChart data={monthly} margin={{top:20,right:8,left:-6,bottom:0}}>
        <CartesianGrid stroke={T.gray200} vertical={false}/>
        <XAxis dataKey="name" tick={{fontSize:9.5,fill:T.ink400}} interval={0} angle={-30} textAnchor="end" height={48} tickLine={false} axisLine={{stroke:T.gray200}}/>
        <YAxis tick={{fontSize:10,fill:T.ink400}} width={38} tickLine={false} axisLine={false} tickFormatter={v=>"$"+v}/>
        <Tooltip cursor={{fill:T.gray100}} content={({active,payload,label})=>active&&payload&&payload[0]?<div className="tip"><div className="tip-l">{label}</div><div className="tip-v">Expected origination: ${(+payload[0].value).toFixed(1)}M</div></div>:null}/>
        <Bar dataKey="total" fill={T.green700} radius={[3,3,0,0]} barSize={26}>
          <LabelList dataKey="total" position="top" formatter={v=>v>0?"$"+v.toFixed(0):""} style={{fontSize:9.5,fill:T.charcoal,fontWeight:600}}/>
        </Bar>
      </BarChart>)}/>

    <Eyebrow style={{marginTop:24}}>Total Expected Origination by Borrower</Eyebrow>
    <ChartFrame title="Total Expected Origination by Borrower ($M)" height={Math.max(160, ranking.length*30+24)} render={()=> (
      <BarChart data={ranking} layout="vertical" margin={{top:4,right:60,left:6,bottom:4}}>
        <XAxis type="number" hide/>
        <YAxis type="category" dataKey="name" width={120} tick={{fontSize:11,fill:T.ink700}} tickLine={false} axisLine={false}/>
        <Tooltip cursor={{fill:T.gray100}} content={({active,payload})=>active&&payload&&payload[0]?<div className="tip"><div className="tip-v">{payload[0].payload.name}: ${payload[0].value.toFixed(1)}M{grand?" · "+pct(payload[0].value/grand):""}</div></div>:null}/>
        <Bar dataKey="value" radius={[0,3,3,0]} barSize={16}>
          {ranking.map((d,k)=><Cell key={k} fill={colorOf[d.name]||T.green700}/>)}
          <LabelList dataKey="value" position="right" formatter={v=>"$"+v.toFixed(1)+"M"} style={{fontSize:9.5,fill:T.ink500}}/>
        </Bar>
      </BarChart>)}/>
  </>;
}

/* ============================ PDF — Executive Summary (jsPDF, branded) ============================ */
let _jspdfPromise=null;
function loadJsPDF(){
  if(typeof window!=="undefined" && window.jspdf && window.jspdf.jsPDF) return Promise.resolve(window.jspdf.jsPDF);
  if(_jspdfPromise) return _jspdfPromise;
  _jspdfPromise=new Promise((resolve,reject)=>{
    const s=document.createElement("script");
    s.src="https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
    s.onload=()=>{ try{ resolve(window.jspdf.jsPDF); }catch(e){ reject(e); } };
    s.onerror=()=>reject(new Error("Could not load PDF library"));
    document.head.appendChild(s);
  });
  return _jspdfPromise;
}
const _hx=h=>{ const n=parseInt(h.replace("#",""),16); return [n>>16&255,n>>8&255,n&255]; };
async function generateFacilityPDF(f, live, meta){
  const jsPDF=await loadJsPDF();
  const doc=new jsPDF({unit:"pt",format:"a4"});
  const W=doc.internal.pageSize.getWidth(), H=doc.internal.pageSize.getHeight();
  const M=48; let y=0;
  const g800=_hx(T.green800), g700=_hx(T.green700), mint=_hx(T.mint300), ink=_hx(T.ink700), ink5=_hx(T.ink500), gr2=_hx(T.gray200);
  // ---- header band ----
  doc.setFillColor(g800[0],g800[1],g800[2]); doc.rect(0,0,W,96,"F");
  try{ doc.addImage(ASSETS.SYMBOL_GREEN,"PNG",M,26,44,44); }catch(e){}
  doc.setTextColor(255,255,255); doc.setFont("helvetica","bold"); doc.setFontSize(17);
  doc.text("ADDEM CAPITAL",M+58,46);
  doc.setFont("helvetica","normal"); doc.setFontSize(10); doc.setTextColor(mint[0],mint[1],mint[2]);
  doc.text("Executive Line Summary · Credit Committee Memo",M+58,64);
  doc.setTextColor(255,255,255); doc.setFontSize(8.5);
  doc.text("CONFIDENTIAL",W-M,40,{align:"right"});
  doc.text(meta.date,W-M,54,{align:"right"});
  y=128;
  // ---- title ----
  doc.setTextColor(...g800); doc.setFont("helvetica","bold"); doc.setFontSize(20);
  doc.text(f.borrower,M,y);
  doc.setFont("helvetica","normal"); doc.setFontSize(12); doc.setTextColor(ink[0],ink[1],ink[2]);
  doc.text(f.facility,M,y+20);
  doc.setFontSize(9.5); doc.setTextColor(ink5[0],ink5[1],ink5[2]);
  doc.text(f.entity||"",M,y+36,{maxWidth:W-2*M});
  y+=58;
  // ---- KPI strip ----
  const kpis=[
    ["Outstanding",live.bal!=null?"$"+live.bal.toFixed(1)+"M":"—"],
    ["Commitment",f.commitment?"$"+f.commitment+"M":"—"],
    ["Interest Rate",rateNum(f.rate)!=null?rateNum(f.rate).toFixed(2)+"%":"—"],
    ["Yield",live.yld!=null?(live.yld*100).toFixed(1)+"%":"—"],
    ["Default Int.",rateNum(f.moratory)!=null?rateNum(f.moratory).toFixed(0)+"%":"—"],
  ];
  const kw=(W-2*M)/kpis.length;
  kpis.forEach((k,i)=>{
    const x=M+i*kw;
    doc.setFillColor(244,248,245); doc.roundedRect(x+(i?4:0),y,kw-8,52,5,5,"F");
    doc.setFontSize(7.5); doc.setTextColor(ink5[0],ink5[1],ink5[2]); doc.setFont("helvetica","bold");
    doc.text(k[0].toUpperCase(),x+12,y+18);
    doc.setFontSize(13); doc.setTextColor(...g800);
    doc.text(String(k[1]),x+12,y+38);
  });
  y+=72;
  // ---- section renderer ----
  const ensure=(need)=>{ if(y+need>H-56){ doc.addPage(); y=64; } };
  const section=(title,rows)=>{
    if(!rows||!rows.length) return;
    ensure(40);
    doc.setFillColor(mint[0],mint[1],mint[2]); doc.rect(M,y,4,14,"F");
    doc.setFont("helvetica","bold"); doc.setFontSize(11); doc.setTextColor(...g800);
    doc.text(title,M+12,y+11); y+=24;
    doc.setFontSize(9.5);
    rows.forEach(r=>{
      const label=r.label, val=String(r.value==null?"—":r.value);
      const labW=150, valW=W-2*M-labW-12;
      const valLines=doc.splitTextToSize(val,valW);
      const rowH=Math.max(16, valLines.length*12+4);
      ensure(rowH+2);
      doc.setFont("helvetica","bold"); doc.setTextColor(ink[0],ink[1],ink[2]);
      doc.text(label,M,y+10,{maxWidth:labW});
      doc.setFont("helvetica","normal"); doc.setTextColor(ink5[0],ink5[1],ink5[2]);
      doc.text(valLines,M+labW+12,y+10);
      y+=rowH;
      doc.setDrawColor(gr2[0],gr2[1],gr2[2]); doc.setLineWidth(0.5); doc.line(M,y,W-M,y);
      y+=4;
    });
    y+=12;
  };
  // economics rows: commitment, rate, default, fees, advance, prepayment, use of proceeds
  const F=f.fields||{};
  const econ=[
    {label:"Facility Type",value:f.type},
    {label:"Commitment Amount",value:F["Commitment Amount"]||(f.commitment?"$"+f.commitment+"M MXN":"—")},
    {label:"Currency",value:f.currency},
    {label:"Interest Rate",value:f.rate},
    {label:"Default Interest",value:f.moratory},
    {label:"Advance Rate",value:F["Advance Rate"]},
    {label:"Prepayment",value:F["Prepayment"]},
    {label:"Use of Proceeds",value:F["Use of Proceeds"]},
  ].filter(r=>r.value);
  // fees as their own block
  const feeRows=Object.keys(F).filter(k=>k.indexOf("Fee · ")===0).map(k=>({label:k.replace("Fee · ","Fee · "),value:F[k]}));
  section("Economics",econ);
  if(feeRows.length) section("Fees",feeRows);
  section("Structure",(f.terms||[]).filter(t=>["Payment Frequency","Availability Period","Amortization","Facility Stages","Draw Mechanics","Interest-only Period","Considered Value (DDA haircut)","Considered Value (DDA)","Effectiveness %","Stages","Hybrid Period","Amortization Period","Disposition Period (Initial)"].indexOf(t.label)>=0).map(t=>({label:t.label,value:t.value})));
  section("Security Package",(f.security||[]).map(r=>({label:r.label,value:r.value})));
  section("Covenants",(f.covenants||[]).map(r=>({label:r.label,value:r.value})));
  // key dates
  const dates=[{label:"Sign Date",value:f.signDate},{label:"Maturity",value:f.maturity}].filter(r=>r.value&&r.value!=="—");
  section("Key Dates",dates);
  if(f.notes){ ensure(60); doc.setFillColor(mint[0],mint[1],mint[2]); doc.rect(M,y,4,14,"F");
    doc.setFont("helvetica","bold"); doc.setFontSize(11); doc.setTextColor(...g800); doc.text("Notes",M+12,y+11); y+=22;
    doc.setFont("helvetica","normal"); doc.setFontSize(9.5); doc.setTextColor(ink5[0],ink5[1],ink5[2]);
    const nl=doc.splitTextToSize(f.notes,W-2*M); ensure(nl.length*12); doc.text(nl,M,y+8); y+=nl.length*12+8;
  }
  // ---- footer on every page ----
  const pages=doc.internal.getNumberOfPages();
  for(let p=1;p<=pages;p++){ doc.setPage(p);
    doc.setDrawColor(gr2[0],gr2[1],gr2[2]); doc.setLineWidth(0.5); doc.line(M,H-40,W-M,H-40);
    doc.setFont("helvetica","normal"); doc.setFontSize(8); doc.setTextColor(ink5[0],ink5[1],ink5[2]);
    doc.text("Addem Capital · Goldberg-Zogovic S.A.P.I. de C.V., SOFOM E.N.R. · Confidential",M,H-26);
    doc.text("Page "+p+" / "+pages,W-M,H-26,{align:"right"});
    doc.text(meta.outstandingNote||"",M,H-14);
  }
  doc.save("Addem_"+f.borrower.replace(/[^A-Za-z0-9]/g,"")+"_"+f.facility.replace(/[^A-Za-z0-9]/g,"")+"_ExecutiveSummary.pdf");
}

/* ============================ Technical Sheet ============================ */
function techNorm(s){ return String(s||"").toLowerCase().normalize("NFKD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z]/g,""); }
function techLive(f){
  const k=techNorm(f.portfolioKey);
  const p=PORTFOLIO.find(x=>techNorm(x.b)===k)||PORTFOLIO.find(x=>techNorm(x.b).startsWith(k)&&k.length>3);
  return p?{bal:p.bal,yld:p.yld,asg:p.asg,st:p.st}:{bal:null,yld:null,asg:null,st:null};
}
function techAvailable(f,live){
  if(!f.commitment||live.bal==null) return "—";
  if(live.bal>f.commitment) return "Fully drawn (book > single-facility line)";
  return "$"+(f.commitment-live.bal).toFixed(1)+"M MXN";
}
function rateNum(s){ const m=String(s||"").match(/([\d.]+)\s*%/); return m?parseFloat(m[1]):null; }
function techAnswer(query){
  const q=query.toLowerCase();
  let f=TECH.find(t=>q.includes(t.borrower.toLowerCase()));
  if(!f) f=TECH.find(t=>techNorm(t.facility).length>3 && q.replace(/[^a-z]/g,"").includes(techNorm(t.facility).slice(0,6)));
  if(!f) f=TECH[0];
  const live=techLive(f); const F=f.fields||{};
  const intents=[
    {keys:["outstanding","balance","saldo","insoluto","drawn"],label:"Outstanding Balance",group:"summary",val: live.bal!=null?("$"+live.bal.toFixed(1)+"M MXN"):"—"},
    {keys:["available","disponible","undrawn"],label:"Available Amount",group:"summary",val: techAvailable(f,live)},
    {keys:["yield"],label:"Yield",group:"summary",val: live.yld!=null?(live.yld*100).toFixed(1)+"%":"—"},
    {keys:["status","estatus"],label:"Status",group:"summary",val: live.st||"Active"},
    {keys:["currency","moneda"],label:"Currency",group:"summary",val:f.currency},
    {keys:["commitment","compromiso","line size","monto del"],label:"Commitment Amount",group:"economics",val:F["Commitment Amount"]},
    {keys:["interest rate","rate","tasa","coupon","pricing"],label:"Interest Rate",group:"economics",val:f.rate},
    {keys:["default interest","moratory","moratori"],label:"Default Interest",group:"economics",val:f.moratory},
    {keys:["fee","fees","comisi","commission"],label:"Fees",group:"economics",val:[F["Fee · Drawdown"],F["Fee · Monitoring"]||F["Fee · Monitoring (servicing)"]].filter(Boolean).join("   |   ")||"Not specified"},
    {keys:["advance rate","borrowing base","considered value","haircut"],label:"Advance Rate / Borrowing Base",group:"economics",val:F["Advance Rate"]||F["Considered Value (DDA)"]||F["Draw Mechanics"]},
    {keys:["maturity","vencimiento","matures","mature"],label:"Maturity",group:"dates",val:f.maturity},
    {keys:["sign date","fecha de firma","origination date"],label:"Sign Date",group:"dates",val:f.signDate},
    {keys:["availability","disposition","disponibilidad"],label:"Availability Period",group:"dates",val:F["Availability Period"]||F["Disposition Period (Initial)"]||"Not specified"},
    {keys:["facility type","type","tipo"],label:"Facility Type",group:"structure",val:f.type},
    {keys:["payment frequency","frequency","frecuencia"],label:"Payment Frequency",group:"structure",val:F["Payment Frequency"]},
    {keys:["amortization","amortiz"],label:"Amortization",group:"dates",val:F["Amortization"]||F["Amortization Period"]},
    {keys:["grace","interest-only","interest only","gracia"],label:"Interest-only / Grace",group:"dates",val:F["Interest-only Period"]||F["Grace Period"]||"Not specified"},
    {keys:["draw mechanics","draw"],label:"Draw Mechanics",group:"structure",val:F["Draw Mechanics"]||F["Advance Rate"]},
    {keys:["prepay","prepayment","pago anticipado"],label:"Prepayment",group:"structure",val:F["Prepayment"]||"Not specified"},
    {keys:["reporting","report"],label:"Reporting Requirements",group:"covenants",val:F["Affirmative covenants"]||"Not specified"},
    {keys:["collateral","colateral","secured","supports"],label:"Collateral",group:"security",val:F["Collateral"]||"Not specified"},
    {keys:["guarantee","guaranties","garant","trust","fideicomiso","obligor"],label:"Guarantees / Trust",group:"security",val:F["Guarantee Trust"]||F["Trust"]||F["Master Trust"]||F["Joint Obligor"]||F["Joint Obligors"]||"Not specified"},
    {keys:["reserve","reserva"],label:"Reserve Accounts",group:"security",val:F["Interest Reserve"]||F["Collateral Reserve"]||"Not specified"},
    {keys:["covenant","covenants","trigger"],label:"Covenants",group:"covenants",val:(f.covenants||[]).map(c=>c.label+": "+c.value).join("   •   ")||"Not specified"},
    {keys:["concentration","concentraci"],label:"Concentration Limits",group:"covenants",val:F["Concentration"]||F["Concentration Limit"]||F["Concentration · State"]||"Not specified"},
    {keys:["eligibility","elegib"],label:"Eligibility",group:"covenants",val:F["Eligibility"]||F["Eligibility Criteria"]||"Not specified"},
  ];
  let hit=intents.find(it=>it.keys.some(k=>q.includes(k)));
  if(!hit){ const fk=Object.keys(F).find(k=>q.includes(k.toLowerCase())); hit=fk?{label:fk,group:"structure",val:F[fk]}:{label:"Facility Overview",group:"summary",val:f.type}; }
  return {fid:f.id, borrower:f.borrower, facility:f.facility, label:hit.label, group:hit.group, val:hit.val};
}
function techBuckets(f){
  const base=[
    {label:"Facility Type",value:f.type},{label:"Currency",value:f.currency},
    {label:"Commitment Amount",value:f.commitment?("$"+f.commitment+"M MXN"):"—"},
    {label:"Interest Rate",value:f.rate},{label:"Default Interest",value:f.moratory},
    {label:"Sign Date",value:f.signDate},{label:"Maturity",value:f.maturity},
  ];
  const all=base.concat(f.summaryExtra||[]).concat(f.terms||[]);
  const b={economics:[],structure:[],dates:[]}; const seen=new Set();
  all.forEach(r=>{ if(!r||!r.value||r.value==="—") return; const key=r.label+"|"+r.value; if(seen.has(key)) return; seen.add(key);
    const L=r.label.toLowerCase();
    if(/period|maturity|date/.test(L)) b.dates.push(r);
    else if(/rate|fee|yield|commitment|amount|considered|cost|class [ab]|default interest|draw amount|min drawn|warrants|advance|reserve/.test(L)) b.economics.push(r);
    else b.structure.push(r);
  });
  return b;
}
function Accordion({ id, title, rows, open, onToggle, hl, innerRef }){
  if(!rows||!rows.length) return null;
  return <div className={"acc"+(hl?" hl":"")} ref={innerRef}>
    <button className="acc-h" onClick={()=>onToggle(id)}>
      <span className="acc-t">{title}<span className="acc-n">{rows.length}</span></span>
      <span className={"acc-x"+(open?" o":"")}>⌄</span>
    </button>
    {open&&<div className="acc-b"><div className="kv">{rows.map((r,k)=><div className="kv-row" key={k}><div className="kv-l">{r.label}</div><div className="kv-v">{r.value}</div></div>)}</div></div>}
  </div>;
}
function SecTechnical({ i, onQ, nav, focus, onClearFocus }){
  const byB={}; TECH.forEach(t=>{(byB[t.borrower]=byB[t.borrower]||[]).push(t);});
  const borrowers=Object.keys(byB);
  const ff = focus&&focus.section==="technical"&&focus.hl&&focus.hl.type==="facility"?focus.hl.key:null;
  const ffB = ff?((TECH.find(t=>t.id===ff)||{}).borrower):null;
  const [selB,setSelB]=useState(ffB||borrowers[0]);
  const [facIdx,setFacIdx]=useState(0);
  const [q,setQ]=useState(""); const [ans,setAns]=useState(null);
  const [openMap,setOpenMap]=useState({economics:true,structure:true,security:false,covenants:false,dates:true});
  const [pdfBusy,setPdfBusy]=useState(false); const [pdfErr,setPdfErr]=useState("");
  const hlRef=useRef(null);
  useEffect(()=>{ if(ffB){ setSelB(ffB); const idx=(byB[ffB]||[]).findIndex(t=>t.id===ff); setFacIdx(idx<0?0:idx); } },[ff]);
  const facs=byB[selB]||[];
  const f=facs[Math.min(facIdx,facs.length-1)]||facs[0];
  const live=techLive(f);
  const totCommit=facs.reduce((s,x)=>s+(x.commitment||0),0);
  const wRate=(()=>{ let wc=0,wr=0; facs.forEach(x=>{ const r=rateNum(x.rate); if(r!=null){ const w=x.commitment||1; wr+=r*w; wc+=w; } }); return wc?wr/wc:null; })();
  const ind=(PORTFOLIO.find(x=>techNorm(x.b)===techNorm(f.portfolioKey))||{}).ind||"—";
  const hlGroup=ans&&ans.borrower===selB?ans.group:null;
  useEffect(()=>{ if(hlGroup){ if(hlGroup!=="summary") setOpenMap(m=>({...m,[hlGroup]:true})); if(hlRef.current) hlRef.current.scrollIntoView({behavior:"smooth",block:"center"}); } },[ans]);
  const ask=(text)=>{ const query=text!=null?text:q; if(!query.trim()) return; const a=techAnswer(query); setSelB(a.borrower); const idx=(byB[a.borrower]||[]).findIndex(t=>t.id===a.fid); setFacIdx(idx<0?0:idx); setAns(a); if(text!=null) setQ(text); };
  const toggle=k=>setOpenMap(m=>({...m,[k]:!m[k]}));
  const downloadPDF=async()=>{ if(pdfBusy) return; setPdfErr(""); setPdfBusy(true);
    try{ await generateFacilityPDF(f, live, { date: monthLong(i), outstandingNote: live.bal!=null?("Outstanding as of "+monthLong(i)+": $"+live.bal.toFixed(1)+"M MXN"):"" }); }
    catch(e){ setPdfErr("Could not generate PDF. Check your connection and try again."); }
    finally{ setPdfBusy(false); } };
  const bk=techBuckets(f);
  const examples=["What is "+selB+"'s outstanding balance?","What is "+selB+"'s interest rate?","What collateral supports "+selB+"?","What is the prepayment for "+selB+"?","What covenants apply to "+selB+"?","What is the maturity of "+selB+"?"];
  const grpName={summary:"Borrower Summary",economics:"Economics",structure:"Structure",security:"Security Package",covenants:"Covenants",dates:"Key Dates"};
  return <>
    <PageHead title="Technical Sheet" sub="Searchable credit knowledge base · understand a borrower and its contracts in under a minute" section="Technical Sheet" onQ={onQ} nav={nav} i={i}/>
    <div className="badge">Contractual data parsed from facility technical sheets · outstanding &amp; yield linked live from the portfolio</div>
    {focus&&focus.section==="technical"&&focus.answer&&<AnswerCard answer={focus.answer} onClear={onClearFocus}/>}

    {/* Borrower selector (names only) */}
    <div className="techbar">
      <div className="techbar-l">
        <div className="tsel-lab">Select Borrower</div>
        <select className="tsel" value={selB} onChange={e=>{ setSelB(e.target.value); setFacIdx(0); setAns(null); setQ(""); }}>
          {borrowers.map(b=><option key={b} value={b}>{b}</option>)}
        </select>
      </div>
      <div className="techbar-r muted2">{borrowers.length} borrowers · {TECH.length} facilities on file</div>
    </div>

    {/* Borrower summary (6 metrics) */}
    <Eyebrow style={{marginTop:18}}>{selB} — borrower summary</Eyebrow>
    <div className={"tiles tiles6"+(hlGroup==="summary"?" hl":"")} ref={hlGroup==="summary"?hlRef:null}>
      <StatTile label="Outstanding Balance" value={live.bal!=null?"$"+live.bal.toFixed(1)+"M":"—"}/>
      <StatTile label="Total Commitment" value={totCommit?"$"+totCommit.toFixed(0)+"M":"—"}/>
      <StatTile label="Facilities" value={facs.length}/>
      <StatTile label="Wtd Avg Rate" value={wRate!=null?wRate.toFixed(1)+"%":"—"}/>
      <StatTile label="Wtd Avg Yield" value={live.yld!=null?pct(live.yld):"—"}/>
      <StatTile label="Industry" value={ind}/>
    </div>

    {/* Facilities table (multi-contract) */}
    {facs.length>1 && <>
      <Eyebrow style={{marginTop:22}}>Facilities · {facs.length} contracts</Eyebrow>
      <div className="card ftab-wrap"><table className="ftab"><thead><tr>
        <th>Facility</th><th>Type</th><th className="num">Commitment</th><th className="num">Rate</th><th>Maturity</th><th>Status</th></tr></thead>
        <tbody>{facs.map((x,k)=><tr key={x.id} className={"ftab-row"+(k===facIdx?" on":"")} onClick={()=>{ setFacIdx(k); setAns(null); }}>
          <td className="ftab-b">{x.facility}</td><td>{x.type}</td>
          <td className="num">{x.commitment?"$"+x.commitment+"M":"—"}</td>
          <td className="num">{rateNum(x.rate)!=null?rateNum(x.rate).toFixed(2)+"%":"—"}</td>
          <td>{x.maturity}</td><td>{(techLive(x).st)||"Active"}</td></tr>)}</tbody></table></div>
    </>}

    {/* Q&A search */}
    <div className="card qa qa-lg">
      <div className="qa-title">Technical Q&amp;A</div>
      <div className="qa-sub">Ask anything about {selB}'s contracts in plain language.</div>
      <div className="qa-row">
        <span className="qa-ic">⌕</span>
        <input className="qa-in" placeholder={"e.g. What is "+selB+"'s interest rate?"} value={q}
          onChange={e=>setQ(e.target.value)} onKeyDown={e=>{ if(e.key==="Enter") ask(); }}/>
        <button className="qa-btn" onClick={()=>ask()}>Ask</button>
      </div>
      <div className="qa-sugg-lab">Suggested questions</div>
      <div className="qa-chips">{examples.map((ex,k)=><button key={k} className="chip" onClick={()=>ask(ex)}>{ex}</button>)}</div>
      {ans&&<div className="qa-ans">
        <div className="qa-ans-h">{ans.borrower} · {ans.facility}</div>
        <div className="qa-ans-l">{ans.label}</div>
        <div className="qa-ans-v">{ans.val||"Not specified in documentation"}</div>
        <div className="qa-ans-src">Source: <b>{grpName[ans.group]||ans.group}</b></div>
      </div>}
    </div>

    {/* Facility tabs + detailed terms */}
    {facs.length>1 && <div className="ftabs">{facs.map((x,k)=><button key={x.id} className={"ftab-pill"+(k===facIdx?" on":"")} onClick={()=>{ setFacIdx(k); setAns(null); }}>{x.facility}</button>)}</div>}
    <div className="terms-head">
      <Eyebrow style={{marginTop:16}}>{f.facility} — contract terms</Eyebrow>
      <button className="dl-btn" onClick={downloadPDF} disabled={pdfBusy} title="Download branded Executive Line Summary (PDF)">
        {pdfBusy
          ? <><span className="dl-spin"/> Generating…</>
          : <><svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Executive Summary · PDF</>}
      </button>
    </div>
    {pdfErr&&<div className="dl-err">{pdfErr}</div>}
    <div className="accs">
      <Accordion id="economics" title="Economics" rows={bk.economics} open={openMap.economics} onToggle={toggle} hl={hlGroup==="economics"} innerRef={hlGroup==="economics"?hlRef:null}/>
      <Accordion id="structure" title="Structure" rows={bk.structure} open={openMap.structure} onToggle={toggle} hl={hlGroup==="structure"} innerRef={hlGroup==="structure"?hlRef:null}/>
      <Accordion id="security" title="Security Package" rows={f.security} open={openMap.security} onToggle={toggle} hl={hlGroup==="security"} innerRef={hlGroup==="security"?hlRef:null}/>
      <Accordion id="covenants" title="Covenants" rows={f.covenants} open={openMap.covenants} onToggle={toggle} hl={hlGroup==="covenants"} innerRef={hlGroup==="covenants"?hlRef:null}/>
      <Accordion id="dates" title="Key Dates" rows={bk.dates} open={openMap.dates} onToggle={toggle} hl={hlGroup==="dates"} innerRef={hlGroup==="dates"?hlRef:null}/>
    </div>
    {f.notes&&<div className="card" style={{marginTop:14}}><Eyebrow>Notes</Eyebrow><div className="note-body">{f.notes}</div></div>}
  </>;
}

function SecPortfolio({ which, i, onQ, focus, onClearFocus , nav }){
  let rows=PORTFOLIO, fac=null, title="Portfolio Overview", sub="Consolidated loan book", section="Portfolio Overview";
  if(which==="Variant"){ rows=PORTFOLIO.filter(x=>x.asg==="Variant"); fac=FACILITY.Variant; title="Variant Portfolio"; sub="Positions assigned to Variant"; section="Variant Portfolio"; }
  if(which==="Covalto"){ rows=PORTFOLIO.filter(x=>x.asg==="Covalto"); fac=FACILITY.Covalto; title="Covalto Portfolio"; sub="Positions assigned to Covalto"; section="Covalto Portfolio"; }
  if(which==="Unassigned"){ rows=PORTFOLIO.filter(x=>x.asg==="Unassigned"); title="Unassigned Portfolio"; sub="Positions retained on balance sheet"; section="Unassigned Portfolio"; }
  const f = focus&&focus.section===which?focus:null;
  const hlBorrower = f&&f.hl&&f.hl.type==="borrower"?f.hl.key:null;
  return <>
    <PageHead title={title} sub={sub+" · as of "+monthLong(i)+" · MXN millions"} section={section} onQ={onQ} nav={nav} i={i}/>
    {f&&<AnswerCard answer={f.answer} onClear={onClearFocus}/>}
    {which==="overview"
      ? <PortfolioOverview rows={rows} i={i} hlBorrower={hlBorrower}/>
      : <PortfolioFlow rows={rows} facility={fac} i={i} hlBorrower={hlBorrower}/>}
  </>;
}

/* ============================ smart navigation + search ============================ */
function textDelta(kind, cur, prev, tag){
  if(prev==null||!isFinite(prev)) return null;
  let s;
  if(kind==="pct"){ const b=(cur-prev)*10000; s=(b>=0?"▲ +":"▼ −")+Math.abs(Math.round(b))+" bps"; }
  else if(kind==="x"){ const d=cur-prev; s=(d>=0?"▲ +":"▼ −")+Math.abs(d).toFixed(2)+"x"; }
  else { const d=prev!==0?(cur-prev)/Math.abs(prev)*100:0; s=(d>=0?"▲ +":"▼ −")+Math.abs(d).toFixed(1)+"%"; }
  return s+" "+tag;
}
function AnswerCard({ answer, onClear }){
  if(!answer) return null;
  return <div className="answer">
    <div className="answer-top"><Eyebrow>Answer</Eyebrow><button className="x" onClick={onClear} aria-label="Dismiss">✕</button></div>
    <div className="answer-title">{answer.title}</div>
    {answer.lines.filter(Boolean).map((l,k)=><div className="answer-line" key={k}>{l}</div>)}
  </div>;
}
function buildSearch(i){
  const E=[]; const prev=i-1, py=i-12;
  const SYN={ roe:"return on equity", roeA:"return on equity", roa:"return on assets", roaA:"return on assets",
    nim:"net interest margin margin", nimA:"net interest margin margin",
    rolp:"yield return on loan portfolio rolp", rolpA:"yield return on loan portfolio rolp",
    de:"leverage debt to equity debt equity gearing", dscr:"debt service coverage ratio",
    intCov:"interest coverage ratio times interest earned",
    cof:"cost of funds funding cost", cofA:"cost of funds funding cost",
    da:"debt to total assets leverage gearing",
    current:"current ratio liquidity", quick:"quick ratio acid test liquidity",
    eqRatio:"equity ratio capitalization" };
  const ACCSYN={ "operating income":"ebitda operating profit operating earnings",
    "net income":"net profit earnings bottom line profit",
    "total income":"revenue total revenue topline sales",
    "total interest income":"interest revenue yield income",
    "net interest income":"nii spread" };
  const synFor=k=>SYN[k]||"";
  (typeof TECH!=="undefined"?TECH:[]).forEach(t=>{
    const norm=s=>String(s||"").toLowerCase().normalize("NFKD").replace(/[\u0300-\u036f]/g,"");
    const p=PORTFOLIO.find(x=>norm(x.b).replace(/[^a-z]/g,"")===norm(t.portfolioKey).replace(/[^a-z]/g,""));
    E.push({ grp:"Technical Sheet", label:t.borrower+" · "+t.facility, sub:"Technical Sheet · contractual terms",
      terms:(t.borrower+" "+t.facility+" "+t.type+" technical sheet contract terms collateral covenants rate maturity").toLowerCase(),
      focus:{ section:"technical", hl:{type:"facility",key:t.id},
        answer:{ title:t.borrower+" — "+t.facility,
          lines:[ p?("Outstanding: $"+p.bal.toFixed(1)+"M  ·  Yield: "+(p.yld>0?pct(p.yld):"—")+"  ·  "+p.asg):"Outstanding: linked from tape",
                  "Rate: "+t.rate+"  ·  Commitment: "+(t.commitment?"$"+t.commitment+"M":"—"),
                  "Maturity: "+t.maturity ] } } });
  });
  KPIS.forEach(k=>{ const cur=k.get(i);
    E.push({ grp:"Metrics", label:k.label, sub:"Executive Summary", terms:(k.label+" "+k.k+" "+synFor(k.k)).toLowerCase(),
      focus:{ section:"executive", hl:{type:"metric",key:k.k},
        answer:{ title:k.label+" — "+fmt(k.kind,cur),
          lines:[ textDelta(k.kind,cur,k.get(prev),"vs "+monthAbbr(prev)), textDelta(k.kind,cur,py>=0?k.get(py):null,"vs "+monthAbbr(py)), k.ex ] } } });
  });
  RATIOS.forEach(([grp,items])=> items.forEach(([key,l,kind,ex])=>{ const cur=g(key,i);
    E.push({ grp:"Ratios", label:l, sub:"Historical Financials", terms:(l+" "+key+" "+synFor(key)).toLowerCase(),
      focus:{ section:"historical", hl:{type:"ratio",key},
        answer:{ title:l+" — "+fmt(kind,cur), lines:[ textDelta(kind,cur,g(key,prev),"vs "+monthAbbr(prev)), ex ] } } });
  }));
  const totBal=PORTFOLIO.reduce((s,x)=>s+x.bal,0);
  PORTFOLIO.forEach(p=>{
    E.push({ grp:"Borrowers", label:p.b, sub:p.ind+" · "+p.asg, terms:(p.b+" "+p.ind+" "+p.asg+" outstanding balance saldo insoluto exposure position yield assignment").toLowerCase(),
      focus:{ section:"overview", hl:{type:"borrower",key:p.b},
        answer:{ title:p.b+" — $"+p.bal.toFixed(1)+"M outstanding",
          lines:[ "Yield: "+(p.yld>0?pct(p.yld):"— (non-accruing)"), "Assignment: "+p.asg+"  ·  Status: "+p.st,
            "Industry: "+p.ind+"  ·  Currency: "+p.cur, "Concentration: "+pct(p.bal/totBal)+" of the book" ] } } });
  });
  [...new Set(PORTFOLIO.map(p=>p.ind))].forEach(ind=>{ const rows=PORTFOLIO.filter(p=>p.ind===ind); const b=rows.reduce((s,x)=>s+x.bal,0);
    E.push({ grp:"Industries", label:ind, sub:"Portfolio Overview", terms:ind.toLowerCase(),
      focus:{ section:"overview", hl:{type:"industry",key:ind},
        answer:{ title:ind+" — $"+b.toFixed(1)+"M ("+pct(b/totBal)+" of book)", lines:[ rows.length+" borrowers", "Largest: "+rows.sort((a,c)=>c.bal-a.bal)[0].b ] } } });
  });
  [["Variant","Variant"],["Covalto","Covalto"],["Unassigned","Unassigned"]].forEach(([asg,page])=>{
    const rows=PORTFOLIO.filter(p=>p.asg===asg); const b=rows.reduce((s,x)=>s+x.bal,0);
    E.push({ grp:"Assignments", label:asg+" Portfolio", sub:"Assignment", terms:asg.toLowerCase(),
      focus:{ section:page, answer:{ title:asg+" Portfolio — $"+b.toFixed(1)+"M", lines:[ rows.length+" positions", pct(b/totBal)+" of total book" ] } } });
  });
  MODEL.stmt.income.concat(MODEL.stmt.balance).filter(a=>a.lvl>0).forEach(a=>{
    const cur=a.v[i]!=null?a.v[i]:0, pv=i>0&&a.v[i-1]!=null?a.v[i-1]:null;
    E.push({ grp:"Statement accounts", label:a.n, sub:"Detailed Financial Statements", terms:(a.n+" "+(ACCSYN[a.n.toLowerCase()]||"")).toLowerCase(),
      focus:{ section:"historical", hl:{type:"account",key:a.n},
        answer:{ title:a.n+" — "+money(cur), lines:[ textDelta("money",cur,pv,"vs "+monthAbbr(i-1)) ] } } });
  });
  [["Operating Income","ebitda operating income operating profit operating earnings"],
   ["Net Income (Loss)","net income net profit earnings bottom line profit"],
   ["Net Income Before Taxes","pretax profit ebt earnings before taxes"],
   ["Total Revenue","revenue topline sales total income"]].forEach(([nm,syn])=>{
    const acc=MODEL.stmt.income.find(a=>a.n===nm); if(!acc) return;
    const cur=acc.v[i]!=null?acc.v[i]:0, pv=i>0&&acc.v[i-1]!=null?acc.v[i-1]:null;
    E.push({ grp:"Statement accounts", label:nm, sub:"Detailed Financial Statements", terms:(nm+" "+syn).toLowerCase(),
      focus:{ section:"historical", hl:{type:"account",key:nm},
        answer:{ title:nm+" — "+money(cur), lines:[ textDelta("money",cur,pv,"vs "+monthAbbr(i-1)) ] } } });
  });
  return E;
}
function predefinedQuestions(i){
  const b=PORTFOLIO[0].b, idx=buildSearch(i);
  const find=(grp,label)=> idx.find(e=>e.grp===grp&&e.label===label);
  const totBal=PORTFOLIO.reduce((s,x)=>s+x.bal,0);
  const topBor=[...PORTFOLIO].sort((a,c)=>c.bal-a.bal).slice(0,3).map(x=>x.b+" ($"+x.bal.toFixed(1)+"M)").join(", ");
  const passive=PORTFOLIO.filter(p=>p.st==="Passive").map(x=>x.b).join(", ")||"none";
  return [
    { q:"What is the outstanding balance of "+b+"?", e:find("Borrowers",b) },
    { q:"Which portfolio contains "+b+"?", e:find("Borrowers",b) },
    { q:"What are the largest borrower exposures?", e:{ focus:{section:"overview", answer:{title:"Largest borrower exposures", lines:[topBor]}}} },
    { q:"Which borrowers belong to the passive portfolio?", e:{ focus:{section:"overview", answer:{title:"Passive portfolio", lines:[passive]}}} },
    { q:"What is the current ROE?", e:find("Metrics","ROE") },
    { q:"What is the current Debt-to-Equity ratio?", e:find("Ratios","Debt / Equity") },
    { q:"What is the current Cost of Funds?", e:find("Metrics","Cost of Funds") },
    { q:"What was Net Income in "+monthLong(i)+"?", e:{ focus:{section:"historical", hl:{type:"account",key:"Net Income"},
        answer:{ title:"Net Income — "+money(g("ni",i)), lines:[ textDelta("money",g("ni",i),g("ni",i-1),"vs "+monthAbbr(i-1)) ] }}} },
    { q:"What changed versus "+monthAbbr(i-1)+"?", e:{ focus:{section:"executive",
        answer:{ title:"Key changes vs "+monthLong(i-1), lines:[
          "Loan Portfolio: "+textDelta("money",g("loan",i),g("loan",i-1),""),
          "Net Interest Margin: "+textDelta("pct",g("nimA",i),g("nimA",i-1),""),
          "Cost of Funds: "+textDelta("pct",g("cofA",i),g("cofA",i-1),""),
          "ROE: "+textDelta("pct",g("roeA",i),g("roeA",i-1),"") ]}}} },
  ].filter(x=>x.e);
}

/* ============================ shell ============================ */
function MiniSearch({ i, nav }){
  const [q,setQ]=useState(""); const [open,setOpen]=useState(false);
  const ql=q.trim().toLowerCase();
  const res=ql.length>=2?(()=>{ const toks=ql.split(/\s+/).filter(w=>w.length>1);
    const sc=e=>{ const hay=(e.label+" "+e.terms).toLowerCase(); if(hay.includes(ql)) return 3; if(e.label.toLowerCase().includes(ql)) return 2; return toks.length&&toks.every(t=>hay.includes(t))?1:0; };
    return buildSearch(i).map(e=>[sc(e),e]).filter(x=>x[0]>0).sort((a,b)=>b[0]-a[0]).slice(0,8).map(x=>x[1]); })():[];
  return <div className="msearch">
    <svg className="msearch-ic" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><circle cx="11" cy="11" r="7"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
    <input className="msearch-in" placeholder="Search…" value={q}
      onChange={e=>{setQ(e.target.value); setOpen(true);}} onFocus={()=>setOpen(true)} onBlur={()=>setTimeout(()=>setOpen(false),160)}/>
    {open&&res.length>0&&<div className="msearch-pop">
      {res.map((r,k)=><button key={k} className="msearch-res" onMouseDown={()=>{ nav(r.focus); setQ(""); setOpen(false); }}>
        <span className="mr-l">{r.label}</span><span className="mr-s">{r.grp} · {r.sub}</span></button>)}
    </div>}
  </div>;
}
function PageHead({ title, sub, badge, section, onQ, nav, i }){
  return <div className="phead">
    {badge&&<div className="badge">{badge}</div>}
    <div className="phead-row">
      <div className="phead-titles"><h1>{title}</h1><div className="phead-sub">{sub}</div></div>
      <div className="phead-tools">
        {nav&&i!=null&&<MiniSearch i={i} nav={nav}/>}
        {section&&<button className="q-btn" onClick={()=>onQ(section)}>Questions</button>}
      </div>
    </div>
  </div>;
}
function Range({ range, setRange }){
  const opts=[["3M",3],["6M",6],["12M",12],["Max","all"]];
  return <div className="seg">{opts.map(([l,v])=><button key={l} className={"seg-b"+(range===v?" on":"")} onClick={()=>setRange(v)}>{l}</button>)}</div>;
}
function PeriodPicker({ histIdx, value, onChange }){
  const [open,setOpen]=useState(false);
  const ref=useRef(null);
  useEffect(()=>{ const h=e=>{ if(ref.current && !ref.current.contains(e.target)) setOpen(false); }; document.addEventListener("mousedown",h); return ()=>document.removeEventListener("mousedown",h); },[]);
  const ordered=histIdx.slice().reverse();
  return <div className="pp" ref={ref}>
    <span className="pp-l">Reporting period</span>
    <button type="button" className={"pp-btn"+(open?" open":"")} onClick={()=>setOpen(o=>!o)} aria-haspopup="listbox" aria-expanded={open}>
      <span className="pp-val">{mLong(months[value].d)}</span>
      {value===lastHist && <span className="pp-tag">Latest</span>}
      <svg className="pp-caret" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round"><polyline points="6 9 12 15 18 9"/></svg>
    </button>
    {open && <ul className="pp-menu" role="listbox">
      {ordered.map(k=><li key={k} role="option" aria-selected={k===value}
        className={"pp-opt"+(k===value?" sel":"")} onClick={()=>{ onChange(k); setOpen(false); }}>
        <span>{mLong(months[k].d)}</span>
        {k===lastHist && <span className="pp-opt-tag">Latest</span>}
      </li>)}
    </ul>}
  </div>;
}
const NAV=[
  ["executive","Executive Summary"],["historical","Historical Financials"],
  ["overview","Portfolio Overview"],["Covalto","Covalto Portfolio"],["Variant","Variant Portfolio"],["Unassigned","Unassigned Portfolio"],
  ["technical","Technical Sheet"],
  ["projections","Projections"],["origination","Draw Forecast"],
  ["questions","Questions & Comments"],
];
function Dashboard({ onLogout, authUser }){
  const [page,setPage]=useState("executive");
  const [open,setOpen]=useState(false);
  const [i,setI]=useState(lastHist);
  const [questions,setQuestions]=useState(seedQuestions);
  const [qa,setQa]=useState(null); // section name when question modal open
  const [focus,setFocus]=useState(null); // smart-navigation target
  const [cmodal,setCmodal]=useState(null); // expanded chart
  useEffect(()=>{ let on=true; store.get(QKEY).then(v=>{ if(on&&Array.isArray(v)&&v.length) setQuestions(v); }); return ()=>{on=false;}; },[]);
  const persist=next=>{ store.set(QKEY,next); return next; };
  const addQuestion=({user,q,section})=>setQuestions(prev=>persist([{ id:Date.now(), date:new Date().toISOString().slice(0,10), user, section, q, status:"Open", responses:[] },...prev]));
  const addResponse=(id,r)=>setQuestions(prev=>persist(prev.map(x=>x.id===id?{...x,responses:[...x.responses,{...r,date:new Date().toISOString().slice(0,10)}]}:x)));
  const setStatus=(id,s)=>setQuestions(prev=>persist(prev.map(x=>x.id===id?{...x,status:s}:x)));
  const histIdx=months.map((m,k)=>m.h===1?k:null).filter(x=>x!=null);
  const go=p=>{ setPage(p); setOpen(false); setFocus(null); };
  const navigate=f=>{ if(!f) return; setFocus(f); setPage(f.section); setOpen(false); };
  return <ExpandCtx.Provider value={setCmodal}><div className="app"><style>{CSS}</style>
    <header className="topbar">
      <button className="ham" onClick={()=>setOpen(true)} aria-label="Open menu"><span/><span/><span/></button>
      <img className="logo" src={ASSETS.LOGO_H_WHITE} alt="Addem Capital"/>
      <div className="topbar-right">
        <PeriodPicker histIdx={histIdx} value={i} onChange={setI}/>
        <button className="logout" onClick={onLogout} title={authUser?("Signed in as "+authUser+" · Sign out"):"Sign out"}>
          <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
          <span className="logout-t">Sign out</span>
        </button>
      </div>
    </header>

    {open&&<div className="scrim" onClick={()=>setOpen(false)}/>}
    <aside className={"drawer"+(open?" open":"")}>
      <div className="drawer-head"><img className="sym" src={ASSETS.SYMBOL_GREEN} alt=""/>
        <div><div className="dh-name">ADDEM CAPITAL</div><div className="dh-sub">Investor Reporting</div></div>
        <button className="x close" onClick={()=>setOpen(false)}>✕</button></div>
      <nav>{NAV.map(([k,l])=><button key={k} className={"navitem"+(page===k?" on":"")} onClick={()=>go(k)}>{l}</button>)}</nav>
      <div className="drawer-foot">Goldberg-Zogovic S.A.P.I. de C.V.<br/>SOFOM, E.N.R.</div>
    </aside>

    <main className="container">
      {page==="executive"&&<SecExecutive i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="historical"&&<SecHistorical i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="projections"&&<SecProjections i={i} onQ={setQa} nav={navigate}/>}
      {page==="origination"&&<SecOrigination i={i} onQ={setQa} nav={navigate}/>}
      {page==="overview"&&<SecPortfolio which="overview" i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="Variant"&&<SecPortfolio which="Variant" i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="Covalto"&&<SecPortfolio which="Covalto" i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="Unassigned"&&<SecPortfolio which="Unassigned" i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="technical"&&<SecTechnical i={i} onQ={setQa} focus={focus} onClearFocus={()=>setFocus(null)} nav={navigate}/>}
      {page==="questions"&&<SecQuestions questions={questions} onRespond={addResponse} onStatus={setStatus} onNavigate={navigate} onNew={addQuestion} i={i}/>}
      <footer className="foot">Addem Capital · Investor reporting portal. Figures in Mexican pesos (MXN). Historical Jan 2025 – Mar 2026; forecast per model scenario. Financial data from the financial model; portfolio figures illustrative pending the Portfolio Tape.</footer>
    </main>

    {qa&&<QuestionsModal section={qa} onClose={()=>setQa(null)} onSubmit={(d)=>{ addQuestion(d); }}/>}
    {cmodal&&<ChartModal data={cmodal} onClose={()=>setCmodal(null)}/>}
  </div></ExpandCtx.Provider>;
}

/* ============================ styles ============================ */
const CSS=`
@import url('https://fonts.googleapis.com/css2?family=Inter+Tight:wght@400;500;600;700&display=swap');
:root{
  --g800:${T.green800};--g700:${T.green700};--g600:${T.green600};--mint:${T.mint300};--mint100:${T.mint100};
  --char:${T.charcoal};--ink7:${T.ink700};--ink5:${T.ink500};--ink4:${T.ink400};
  --gr3:${T.gray300};--gr2:${T.gray200};--gr1:${T.gray100};--off:${T.offwhite};--neg:${T.neg};
  --sans:'Inter Tight',-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;
}
*{box-sizing:border-box}
.app{font-family:var(--sans);font-weight:400;background:var(--off);color:var(--ink7);min-height:100vh;-webkit-font-smoothing:antialiased}
.num{font-variant-numeric:tabular-nums}
.eyebrow{font-size:11px;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--ink5)}

.topbar{position:sticky;top:0;z-index:40;background:var(--g800);display:grid;grid-template-columns:52px 1fr auto;align-items:center;gap:10px;padding:12px 14px;min-height:66px}
.ham{background:rgba(247,247,247,.12);border:1px solid rgba(247,247,247,.22);border-radius:10px;width:48px;height:48px;display:flex;flex-direction:column;justify-content:center;align-items:center;gap:5px;cursor:pointer;padding:12px;-webkit-tap-highlight-color:transparent}
.ham span{display:block;width:100%;height:2.5px;background:var(--off);border-radius:2px}
.logo{height:24px;width:auto;justify-self:center;object-fit:contain}
.topbar-right{justify-self:end;display:flex;align-items:center;gap:10px}

/* Modern branded date picker */
.pp{position:relative;display:flex;flex-direction:column;align-items:flex-end;gap:3px}
.pp-l{font-size:9px;font-weight:600;letter-spacing:.09em;text-transform:uppercase;color:rgba(247,247,247,.55)}
.pp-btn{display:flex;align-items:center;gap:8px;background:rgba(247,247,247,.1);border:1px solid rgba(247,247,247,.22);border-radius:10px;
  padding:8px 12px;font-family:var(--sans);color:#fff;cursor:pointer;transition:background .16s,border-color .16s,box-shadow .16s;-webkit-tap-highlight-color:transparent}
.pp-btn:hover{background:rgba(247,247,247,.17);border-color:rgba(247,247,247,.4)}
.pp-btn:active{background:rgba(247,247,247,.22)}
.pp-btn.open{background:rgba(247,247,247,.2);border-color:var(--mint);box-shadow:0 0 0 3px rgba(176,235,194,.18)}
.pp-val{font-size:14px;font-weight:600;letter-spacing:-.01em;white-space:nowrap}
.pp-tag{font-size:8.5px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;color:var(--g800);background:var(--mint);padding:2px 6px;border-radius:5px}
.pp-caret{color:rgba(247,247,247,.8);transition:transform .2s}
.pp-btn.open .pp-caret{transform:rotate(180deg)}
.pp-menu{position:absolute;top:calc(100% + 8px);right:0;z-index:60;min-width:230px;max-height:340px;overflow-y:auto;list-style:none;margin:0;padding:6px;
  background:#fff;border:1px solid var(--gr2);border-radius:12px;box-shadow:0 18px 44px rgba(13,71,61,.22);animation:ppIn .16s ease}
@keyframes ppIn{from{opacity:0;transform:translateY(-6px)}to{opacity:1;transform:translateY(0)}}
.pp-opt{display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 12px;border-radius:8px;cursor:pointer;
  font-size:14px;color:var(--ink7);transition:background .12s}
.pp-opt:hover{background:var(--off)}
.pp-opt.sel{background:var(--mint100);color:var(--g800);font-weight:600}
.pp-opt-tag{font-size:8.5px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;color:var(--g700);background:var(--mint);padding:2px 6px;border-radius:5px}

.logout{display:flex;align-items:center;gap:7px;background:rgba(247,247,247,.08);border:1px solid rgba(247,247,247,.2);border-radius:10px;
  height:42px;padding:0 13px;color:rgba(247,247,247,.92);font-family:var(--sans);font-size:13px;font-weight:600;cursor:pointer;
  transition:background .16s,border-color .16s;-webkit-tap-highlight-color:transparent}
.logout:hover{background:rgba(247,247,247,.16);border-color:rgba(247,247,247,.38);color:#fff}
.logout:active{background:rgba(247,247,247,.22)}
.logout-t{display:none}

.scrim{position:fixed;inset:0;background:rgba(31,31,31,.45);z-index:45}
.drawer{position:fixed;top:0;left:0;bottom:0;width:300px;max-width:84vw;background:#fff;z-index:50;transform:translateX(-104%);transition:transform .26s cubic-bezier(.16,1,.3,1);box-shadow:0 18px 40px rgba(13,71,61,.18);display:flex;flex-direction:column}
.drawer.open{transform:translateX(0)}
.drawer-head{display:flex;align-items:center;gap:12px;padding:22px 20px;border-bottom:1px solid var(--gr2);position:relative}
.sym{width:38px;height:38px;object-fit:contain}
.dh-name{font-size:13px;font-weight:600;letter-spacing:.1em;color:var(--g800)}
.dh-sub{font-size:12px;color:var(--ink5)}
.close{position:absolute;right:14px;top:18px}
.drawer nav{padding:10px 0;flex:1;overflow-y:auto}
.navitem{display:block;width:100%;text-align:left;background:none;border:none;padding:14px 22px;font-family:var(--sans);font-size:15px;color:var(--ink7);cursor:pointer;border-left:3px solid transparent}
.navitem:hover{background:var(--off)}
.navitem.on{color:var(--g800);font-weight:600;border-left-color:var(--g800);background:var(--mint100)}
.drawer-foot{padding:18px 22px;font-size:10.5px;letter-spacing:.04em;color:var(--ink4);border-top:1px solid var(--gr2)}

.container{max-width:1200px;margin:0 auto;padding:26px 18px 56px}
.phead{margin-bottom:22px}
.phead-row{display:flex;align-items:flex-start;justify-content:space-between;gap:12px}
.phead h1{font-size:30px;font-weight:600;color:var(--char);letter-spacing:-.02em;line-height:1.05}
.phead-sub{font-size:13px;color:var(--ink5);margin-top:8px}
.q-btn{flex:0 0 auto;background:#fff;border:1px solid var(--gr3);color:var(--g800);font-family:var(--sans);font-weight:600;font-size:13px;padding:9px 16px;border-radius:999px;cursor:pointer}
.q-btn:hover{background:var(--mint100);border-color:var(--g600)}
.badge{display:inline-block;font-size:10px;font-weight:600;letter-spacing:.06em;text-transform:uppercase;color:var(--g700);background:var(--mint);padding:4px 10px;border-radius:999px;margin-bottom:12px}

.kpi-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}
.kpi{background:#fff;border:1px solid var(--gr2);border-radius:14px;padding:18px 16px;box-shadow:0 1px 3px rgba(31,31,31,.04);display:flex;flex-direction:column;gap:10px}
.kpi-val{font-size:26px;font-weight:600;color:var(--char);font-variant-numeric:tabular-nums;letter-spacing:-.01em}
.kpi-deltas{display:flex;flex-direction:column;gap:3px}
.delta{font-size:12px;font-weight:500;font-variant-numeric:tabular-nums}
.delta .muted,.muted{color:var(--ink4);font-weight:400}
.kpi-ex{font-size:12.5px;line-height:1.45;color:var(--ink5)}
.hint{font-weight:400;letter-spacing:0;text-transform:none;color:var(--ink4)}
.hero{display:grid;grid-template-columns:1fr 1fr;gap:1px;background:var(--g700);border-radius:16px;overflow:hidden;box-shadow:0 10px 30px rgba(13,71,61,.18)}
.hero-cell{background:var(--g800);padding:18px 18px 16px;display:flex;flex-direction:column;gap:7px}
.hero-label{font-size:10.5px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:var(--mint)}
.hero-val{font-size:27px;font-weight:600;color:#fff;font-variant-numeric:tabular-nums;letter-spacing:-.02em;line-height:1}
.hero-delta{display:flex;flex-direction:column;gap:2px;align-items:flex-start;margin-top:2px}
.hero-delta .delta{font-size:11.5px}
.hero-delta .delta .muted{color:rgba(247,247,247,.55)}
.hero-delta .muted2{font-size:11.5px;color:rgba(247,247,247,.6)}

.card{background:#fff;border:1px solid var(--gr2);border-radius:14px;padding:16px;box-shadow:0 1px 3px rgba(31,31,31,.04);margin-bottom:14px}
.card.pad0{padding:0;overflow:hidden}
.card.chart .eyebrow{margin-bottom:6px}
.legend{display:flex;gap:16px;font-size:11px;font-weight:500;margin:2px 0 4px 2px;flex-wrap:wrap}
.grid2{display:grid;grid-template-columns:1fr;gap:14px}
.band{display:flex;align-items:center;justify-content:space-between;margin:28px 2px 12px}

.tcards{display:grid;grid-template-columns:1fr 1fr;gap:12px}
.tcard{display:flex;flex-direction:column;gap:8px}
.tcard-row{display:flex;align-items:center;justify-content:space-between;gap:8px}
.tcard-val{font-size:21px;font-weight:600;color:var(--char);font-variant-numeric:tabular-nums}

.grp{font-size:11px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:var(--g800);background:var(--off);padding:11px 16px;border-bottom:1px solid var(--gr2)}
.tbl{width:100%;border-collapse:collapse;font-size:14px}
.tbl th{text-align:right;font-size:10px;font-weight:600;letter-spacing:.05em;text-transform:uppercase;color:var(--ink4);padding:11px 16px;border-bottom:1px solid var(--gr2);white-space:nowrap}
.tbl th:first-child{text-align:left}
.tbl td{padding:12px 16px;border-bottom:1px solid var(--gr1);vertical-align:top;color:var(--ink7)}
.tbl tr:last-child td{border-bottom:none}
.num{text-align:right;font-size:13px;white-space:nowrap;color:var(--char);font-variant-numeric:tabular-nums}
.num.b{font-weight:600}
.sub{font-size:11.5px;color:var(--ink4);line-height:1.35;margin-top:3px}
td.sub{font-size:12px;color:var(--ink5)}

.tiles{display:grid;grid-template-columns:1fr 1fr;gap:12px}
.tile{background:#fff;border:1px solid var(--gr2);border-radius:12px;padding:15px 14px;display:flex;flex-direction:column;gap:8px}
.tile-v{font-size:21px;font-weight:600;color:var(--char);font-variant-numeric:tabular-nums}

.flow{display:flex;gap:14px;align-items:baseline;margin:30px 2px 14px}
.flow-n{font-size:12px;font-weight:600;color:var(--g600);letter-spacing:.08em}
.flow-t{font-size:19px;font-weight:600;color:var(--char);letter-spacing:-.01em}
.flow-s{font-size:13px;color:var(--ink5)}

.donut{display:flex;align-items:center;gap:8px;margin-top:4px}
.legend-list{flex:1;font-size:13px}
.ll-row{display:flex;justify-content:space-between;gap:8px;padding:3px 0}
.ll-name{display:flex;align-items:center;gap:8px;color:var(--ink7)}
.sw{width:9px;height:9px;border-radius:2px;display:inline-block}
.ll-val{font-size:12px;color:var(--char);font-variant-numeric:tabular-nums;font-weight:500}
.note{font-size:11.5px;color:var(--ink4);margin-top:8px;line-height:1.45}

.tip{background:var(--char);color:#fff;padding:8px 10px;border-radius:8px;font-size:11px;font-variant-numeric:tabular-nums}
.tip-l{opacity:.65;margin-bottom:3px}
.tip-v{white-space:nowrap}

.seg{display:inline-flex;border:1px solid var(--gr2);border-radius:8px;overflow:hidden;background:#fff}
.seg-b{background:none;border:none;border-right:1px solid var(--gr2);padding:7px 13px;font-family:var(--sans);font-size:11px;font-weight:500;color:var(--ink5);cursor:pointer}
.seg-b:last-child{border-right:none}
.seg-b.on{background:var(--g800);color:#fff}

/* scorecard */
.score-row{display:grid;grid-template-columns:1fr auto auto;grid-template-areas:'name spark val' 'name spark delta';gap:4px 14px;align-items:center;padding:13px 16px;border-bottom:1px solid var(--gr1)}
.score-row:last-child{border-bottom:none}
.score-name{grid-area:name;font-size:13.5px;color:var(--ink7)}
.score-spark{grid-area:spark}
.score-val{grid-area:val;font-size:16px;font-weight:600;color:var(--char);font-variant-numeric:tabular-nums;text-align:right}
.score-delta{grid-area:delta;text-align:right;display:flex;flex-direction:column;gap:1px;align-items:flex-end}

/* detailed statements */
.stmt-head{width:100%;display:flex;align-items:center;justify-content:space-between;background:var(--off);border:none;padding:13px 16px;cursor:pointer;border-bottom:1px solid var(--gr2)}
.grp-inline{font-size:13px;font-weight:600;color:var(--g800)}
.stmt-toggle{font-size:11px;font-weight:600;color:var(--ink5)}
.stmt-search{display:flex;align-items:center;justify-content:space-between;gap:10px;padding:10px 16px;border-bottom:1px solid var(--gr1)}
.stmt-cols{font-size:10px;font-weight:600;letter-spacing:.05em;text-transform:uppercase;color:var(--ink4);white-space:nowrap}
.stmt-tbl td{padding:9px 16px}
.lvl-h td{font-size:10px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--g700);background:#fff;padding-top:14px;border-bottom:1px solid var(--gr2)}
.lvl-l td:first-child{color:var(--ink7);padding-left:24px}
.lvl-t td{font-weight:600;color:var(--char);border-top:1px solid var(--gr2)}
.chgcol{font-weight:500}

/* questions */
.qcard{padding:16px}
.qmeta{display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:8px}
.chip{font-size:11px;font-weight:600;padding:4px 10px;border-radius:999px;white-space:nowrap}
.qsec{font-size:12px;font-weight:600;color:var(--g800)}
.qdot{color:var(--ink4)}
.qdate,.quser{font-size:12px;color:var(--ink5)}
.status-sel{margin-left:auto;border:1px solid var(--gr3);border-radius:7px;padding:5px 8px;font-family:var(--sans);font-size:12px;color:var(--ink7);background:#fff}
.qtext{font-size:15px;color:var(--char);line-height:1.5;margin-bottom:10px}
.responses{border-left:2px solid var(--mint);padding-left:14px;margin:10px 0;display:flex;flex-direction:column;gap:10px}
.resp-meta{font-size:11px;color:var(--ink4);margin-bottom:2px}
.resp-text{font-size:14px;color:var(--ink7);line-height:1.45}
.link-btn{background:none;border:none;color:var(--g700);font-family:var(--sans);font-weight:600;font-size:13px;cursor:pointer;padding:4px 0}
.resp-form{margin-top:10px;display:flex;flex-direction:column;gap:8px}
.empty{padding:30px 16px;text-align:center;color:var(--ink5);font-size:14px}

/* modal + inputs */
.modal-wrap{position:fixed;inset:0;background:rgba(31,31,31,.5);z-index:60;display:flex;align-items:flex-end;justify-content:center;padding:0}
.modal{background:#fff;width:100%;max-width:560px;border-radius:18px 18px 0 0;padding:22px 20px calc(22px + env(safe-area-inset-bottom));display:flex;flex-direction:column;gap:12px;box-shadow:0 -18px 40px rgba(13,71,61,.18)}
.modal-head{display:flex;align-items:flex-start;justify-content:space-between;gap:10px}
.modal-head h3{font-size:18px;font-weight:600;color:var(--char);margin-top:4px}
.in{height:46px;border:1px solid var(--gr3);border-radius:10px;padding:0 13px;font-family:var(--sans);font-size:14px;background:#fff;color:var(--ink7);width:100%}
.in.sm{height:38px;font-size:13px}
.in:focus{outline:none;border-color:var(--g600);box-shadow:0 0 0 3px rgba(26,111,95,.18)}
.ta{height:104px;padding:11px 13px;resize:vertical;line-height:1.5}
.ta.sm{height:74px}
.modal-foot{display:flex;gap:10px;justify-content:flex-end}
.btn{height:46px;border:none;border-radius:10px;background:var(--g800);color:#fff;font-family:var(--sans);font-size:14px;font-weight:600;cursor:pointer;padding:0 20px}
.btn:hover{background:var(--g700)}
.btn:disabled{opacity:.45;cursor:not-allowed}
.btn.ghost{background:#fff;color:var(--ink7);border:1px solid var(--gr3)}
.x{background:none;border:none;color:var(--ink4);cursor:pointer;font-size:15px}
.x:hover{color:var(--neg)}

.tiles-col{grid-template-columns:1fr!important}
.tcard.clickable{cursor:pointer;transition:box-shadow .15s,transform .15s}
.tcard.clickable:hover{box-shadow:0 6px 20px rgba(13,71,61,.14);transform:translateY(-1px)}
.tcard-top{display:flex;align-items:center;justify-content:space-between;gap:6px}
.score-row.clickable{cursor:pointer}
.score-row.clickable:hover{background:var(--mint100)}
.iconbtn.xs{width:22px;height:22px;border-radius:6px}
.iconbtn.sm{width:24px;height:24px}
.legend.wrap{flex-wrap:wrap}
.phead-titles{min-width:0}
.phead-tools{display:flex;align-items:center;gap:10px;flex:0 0 auto}
.msearch{position:relative;display:flex;align-items:center}
.msearch-ic{position:absolute;left:9px;color:var(--ink4);pointer-events:none}
.msearch-in{height:34px;width:150px;padding:0 10px 0 28px;border:1px solid var(--gr2);border-radius:9px;background:#fff;font-family:var(--sans);font-size:12.5px;color:var(--char);outline:none}
.msearch-in:focus{border-color:var(--g600);width:188px}
.msearch-pop{position:absolute;top:40px;right:0;width:300px;max-width:80vw;background:#fff;border:1px solid var(--gr2);border-radius:11px;box-shadow:0 16px 40px rgba(13,71,61,.18);padding:6px;z-index:40;max-height:340px;overflow:auto}
.msearch-res{display:flex;flex-direction:column;align-items:flex-start;gap:1px;width:100%;text-align:left;background:none;border:none;border-radius:7px;padding:8px 10px;cursor:pointer;font-family:var(--sans)}
.msearch-res:hover{background:var(--mint100)}
.mr-l{font-size:13px;font-weight:500;color:var(--char)}
.mr-s{font-size:10.5px;color:var(--ink4)}
.pcards{display:grid;grid-template-columns:1fr;gap:14px}
.pcard-row{display:flex;align-items:center;gap:12px;margin:6px 0}
.pcard-col{flex:1}
.pcard-lab{font-size:10px;letter-spacing:.06em;text-transform:uppercase;color:var(--ink4)}
.pcard-now{font-size:16px;font-weight:600;color:var(--ink7);font-variant-numeric:tabular-nums}
.pcard-proj{font-size:18px;font-weight:600;color:var(--g800);font-variant-numeric:tabular-nums}
.pcard-arrow{color:var(--g600);font-size:16px}
.techbar{display:flex;align-items:flex-end;justify-content:space-between;gap:14px;margin:14px 0 4px;flex-wrap:wrap}
.tsel-lab{font-size:10px;letter-spacing:.07em;text-transform:uppercase;color:var(--ink4);margin-bottom:5px}
.tsel{height:42px;min-width:240px;max-width:100%;padding:0 14px;border:1px solid var(--gr2);border-radius:11px;background:#fff;font-family:var(--sans);font-size:14px;font-weight:500;color:var(--char);outline:none;cursor:pointer}
.tsel:focus{border-color:var(--g600)}
.techbar-r{align-self:flex-end;padding-bottom:12px}
.qa{margin-top:8px}
.qa-row{display:flex;gap:8px;margin-top:8px}
.qa-in{flex:1;height:44px;padding:0 14px;border:1px solid var(--gr2);border-radius:11px;background:#fff;font-family:var(--sans);font-size:14px;color:var(--char);outline:none}
.qa-in:focus{border-color:var(--g600)}
.qa-btn{height:44px;padding:0 20px;border:none;border-radius:11px;background:var(--g800);color:#fff;font-family:var(--sans);font-size:13.5px;font-weight:600;cursor:pointer}
.qa-btn:hover{background:var(--g700)}
.qa-chips{display:flex;flex-wrap:wrap;gap:7px;margin-top:10px}
.chip{border:1px solid var(--gr2);background:var(--mint100);color:var(--g800);border-radius:999px;padding:6px 12px;font-family:var(--sans);font-size:11.5px;cursor:pointer}
.chip:hover{background:var(--mint);border-color:var(--g600)}
.qa-ans{margin-top:14px;border:1px solid var(--mint);background:linear-gradient(180deg,var(--mint100),#fff);border-radius:12px;padding:14px 16px}
.qa-ans-h{font-size:11px;letter-spacing:.05em;text-transform:uppercase;color:var(--g600);font-weight:600}
.qa-ans-l{font-size:12px;color:var(--ink5);margin-top:6px}
.qa-ans-v{font-size:16px;color:var(--char);font-weight:600;margin-top:2px;line-height:1.4}
.qa-ans-src{font-size:11.5px;color:var(--ink4);margin-top:8px}
.kvcard{margin-top:14px}
.kvcard.hl{border-color:var(--g600);box-shadow:0 0 0 3px rgba(26,111,95,.12)}
.kv{display:grid;grid-template-columns:1fr;gap:0;margin-top:8px}
.kv-row{display:grid;grid-template-columns:200px 1fr;gap:14px;padding:9px 0;border-bottom:1px solid var(--gr1)}
.kv-row:last-child{border-bottom:none}
.kv-l{font-size:12px;color:var(--ink5);font-weight:500}
.kv-v{font-size:13px;color:var(--char);line-height:1.45}
.note-body{font-size:12.5px;color:var(--ink5);line-height:1.5;margin-top:6px}
.tiles6{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}
.tiles6.hl{outline:2px solid var(--g600);outline-offset:4px;border-radius:14px}
.ftab-wrap{margin-top:10px;padding:6px 6px 2px;overflow-x:auto}
.ftab{width:100%;border-collapse:collapse;font-size:12.5px}
.ftab thead th{text-align:left;font-size:10px;letter-spacing:.05em;text-transform:uppercase;color:var(--ink4);font-weight:600;padding:8px 10px;border-bottom:1px solid var(--gr2)}
.ftab th.num,.ftab td.num{text-align:right;font-variant-numeric:tabular-nums}
.ftab-row{cursor:pointer;border-bottom:1px solid var(--gr1)}
.ftab-row:hover{background:var(--mint100)}
.ftab-row.on{background:var(--mint100)}
.ftab-row.on .ftab-b{color:var(--g800)}
.ftab td{padding:9px 10px;color:var(--ink7)}
.ftab-b{font-weight:600;color:var(--char)}
.ftabs{display:flex;flex-wrap:wrap;gap:7px;margin-top:18px}
.terms-head{display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap}
.dl-btn{display:inline-flex;align-items:center;gap:8px;background:var(--g800);color:#fff;border:none;border-radius:10px;padding:10px 16px;font-family:var(--sans);font-size:13px;font-weight:600;cursor:pointer;transition:background .16s,opacity .16s;margin-top:14px;-webkit-tap-highlight-color:transparent}
.dl-btn:hover{background:var(--g700)}
.dl-btn:active{background:var(--g900)}
.dl-btn:disabled{opacity:.6;cursor:default}
.dl-spin{width:14px;height:14px;border:2px solid rgba(255,255,255,.35);border-top-color:#fff;border-radius:50%;display:inline-block;animation:dlspin .7s linear infinite}
@keyframes dlspin{to{transform:rotate(360deg)}}
.dl-err{color:var(--neg);font-size:12.5px;font-weight:500;margin-top:8px}
.ftab-pill{border:1px solid var(--gr2);background:#fff;color:var(--ink7);border-radius:999px;padding:7px 14px;font-family:var(--sans);font-size:12px;font-weight:500;cursor:pointer}
.ftab-pill.on{background:var(--g800);color:#fff;border-color:var(--g800)}
.qa-lg{margin-top:18px;padding:22px 22px 20px}
.qa-title{font-size:17px;font-weight:600;color:var(--char);font-family:var(--serif,var(--sans))}
.qa-sub{font-size:12.5px;color:var(--ink5);margin-top:3px}
.qa-row{position:relative;display:flex;gap:10px;margin-top:14px;align-items:center}
.qa-ic{position:absolute;left:16px;font-size:18px;color:var(--ink4);pointer-events:none}
.qa-in{flex:1;height:54px;padding:0 16px 0 42px;border:1px solid var(--gr2);border-radius:13px;background:var(--off,#fff);font-family:var(--sans);font-size:15px;color:var(--char);outline:none}
.qa-in:focus{border-color:var(--g600);box-shadow:0 0 0 3px rgba(26,111,95,.10)}
.qa-btn{height:54px;padding:0 26px;border:none;border-radius:13px;background:var(--g800);color:#fff;font-family:var(--sans);font-size:14px;font-weight:600;cursor:pointer}
.qa-btn:hover{background:var(--g700)}
.qa-sugg-lab{font-size:10.5px;letter-spacing:.06em;text-transform:uppercase;color:var(--ink4);margin:16px 0 8px}
.accs{display:flex;flex-direction:column;gap:10px;margin-top:6px}
.acc{border:1px solid var(--gr2);border-radius:13px;background:#fff;overflow:hidden}
.acc.hl{border-color:var(--g600);box-shadow:0 0 0 3px rgba(26,111,95,.12)}
.acc-h{width:100%;display:flex;align-items:center;justify-content:space-between;background:none;border:none;padding:15px 18px;cursor:pointer;font-family:var(--sans)}
.acc-t{display:flex;align-items:center;gap:10px;font-size:13.5px;font-weight:600;color:var(--char);letter-spacing:.02em}
.acc-n{display:inline-flex;align-items:center;justify-content:center;min-width:20px;height:20px;padding:0 6px;border-radius:999px;background:var(--mint100);color:var(--g700);font-size:10.5px;font-weight:600}
.acc-x{font-size:15px;color:var(--ink4);transition:transform .18s}
.acc-x.o{transform:rotate(180deg)}
.acc-b{padding:2px 18px 14px}
@keyframes hlpulse{0%{box-shadow:0 0 0 0 rgba(26,111,95,.40)}70%{box-shadow:0 0 0 12px rgba(26,111,95,0)}100%{box-shadow:0 0 0 0 rgba(26,111,95,0)}}
.kpi.hl,.tcard.hl,.score-row.hl,.hl-row,.kvcard.hl,.acc.hl,.tiles6.hl,.stat.hl{animation:hlpulse 1.7s ease-out 1}
.foot{margin-top:32px;border-top:1px solid var(--gr2);padding-top:16px;font-size:10.5px;color:var(--ink4);line-height:1.6}

/* chart expand */
.chart-top{display:flex;align-items:center;justify-content:space-between;gap:8px;margin-bottom:6px}
.iconbtn{background:none;border:1px solid var(--gr2);border-radius:7px;width:28px;height:28px;display:flex;align-items:center;justify-content:center;color:var(--ink5);cursor:pointer;flex:0 0 auto}
.iconbtn:hover{background:var(--mint100);border-color:var(--g600);color:var(--g700)}
.card.hl,.kpi.hl{box-shadow:0 0 0 2px var(--g600),0 6px 20px rgba(13,71,61,.14);border-color:var(--g600)}
.hl-row td{background:var(--mint100)!important;box-shadow:inset 3px 0 0 var(--g600)}
.cmodal-wrap{position:fixed;inset:0;background:rgba(31,31,31,.55);z-index:70;display:flex;align-items:center;justify-content:center;padding:16px;animation:fade .18s ease}
.cmodal{background:#fff;width:100%;max-width:980px;border-radius:16px;padding:18px 18px 16px;display:flex;flex-direction:column;box-shadow:0 24px 60px rgba(13,71,61,.28);animation:pop .22s cubic-bezier(.16,1,.3,1)}
.cmodal-head{display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:8px}
.cmodal-title{font-size:16px;font-weight:600;color:var(--char)}
.cmodal-chart{height:72vh;max-height:640px;width:100%}
@keyframes fade{from{opacity:0}to{opacity:1}}
@keyframes pop{from{opacity:0;transform:translateY(12px) scale(.98)}to{opacity:1;transform:none}}

/* answer card */
.answer{background:var(--mint100);border:1px solid var(--mint);border-left:4px solid var(--g700);border-radius:12px;padding:14px 16px;margin-bottom:16px}
.answer-top{display:flex;align-items:center;justify-content:space-between}
.answer-title{font-size:18px;font-weight:600;color:var(--g800);margin:4px 0 6px;letter-spacing:-.01em}
.answer-line{font-size:13.5px;color:var(--ink7);line-height:1.5}

/* search + quick questions */
.searchcard{padding:16px}
.in.search{height:50px;font-size:15px;margin-top:8px}
.res-grp{margin-top:12px}
.res-grp-h{font-size:10px;font-weight:600;letter-spacing:.08em;text-transform:uppercase;color:var(--ink4);margin:8px 2px 4px}
.res{display:flex;align-items:center;gap:10px;width:100%;text-align:left;background:#fff;border:1px solid var(--gr2);border-radius:9px;padding:11px 13px;margin-bottom:6px;cursor:pointer;font-family:var(--sans)}
.res:hover{background:var(--mint100);border-color:var(--g600)}
.res-l{font-size:14px;font-weight:500;color:var(--char)}
.res-s{font-size:11.5px;color:var(--ink4);margin-left:2px}
.res-go{margin-left:auto;font-size:12px;font-weight:600;color:var(--g700)}
.res-empty{font-size:13px;color:var(--ink5);padding:10px 2px}
.chips{display:flex;flex-wrap:wrap;gap:8px}
.qchip{background:#fff;border:1px solid var(--gr2);border-radius:999px;padding:9px 14px;font-size:13px;color:var(--ink7);cursor:pointer;font-family:var(--sans)}
.qchip:hover{background:var(--g800);color:#fff;border-color:var(--g800)}
.q-btn.sm{height:auto;padding:7px 14px;font-size:12px}

@media(min-width:720px){
  .kpi-grid{grid-template-columns:repeat(3,1fr);gap:16px}
  .pcards{grid-template-columns:repeat(3,1fr)}
  .tiles6{grid-template-columns:repeat(6,1fr)}
  .kv-row{grid-template-columns:240px 1fr}
  .tcards{grid-template-columns:repeat(3,1fr)}
  .hero{grid-template-columns:repeat(4,1fr)}
  .tiles{grid-template-columns:repeat(4,1fr)}
  .grid2{grid-template-columns:1fr 1fr}
  .phead h1{font-size:36px}
  .kpi-val{font-size:28px}
  .logo{height:26px}
  .modal-wrap{align-items:center}
  .modal{border-radius:18px}
  .logout-t{display:inline}
}
@media(min-width:1080px){
  .kpi-grid{grid-template-columns:repeat(4,1fr)}
  .container{padding:30px 28px 60px}
}
@media(min-width:1440px){
  .container{max-width:1320px;padding:34px 36px 64px}
  .phead h1{font-size:40px}
}
@media(min-width:1920px){
  .container{max-width:1640px;padding:40px 56px 72px}
  .kpi-grid{gap:20px}
  .grid2{gap:20px}
}
@media(min-width:2560px){
  .container{max-width:2040px}
}
/* overflow safety: nothing breaks out of the viewport */
.app{overflow-x:hidden}
img,svg{max-width:100%}
.recharts-responsive-container{max-width:100%!important}
.tbl-wrap,.table-wrap,.scroll-x{overflow-x:auto;-webkit-overflow-scrolling:touch}
.card.pad0{overflow-x:auto;-webkit-overflow-scrolling:touch}
table{max-width:100%}
@media(max-width:719px){
  .pp-val{font-size:13px}
  .pp-menu{min-width:200px}
  .container{padding:20px 14px 48px}
}
@media (prefers-reduced-motion:reduce){.drawer{transition:none}.pp-menu{animation:none}}
`;

/* ============================ Branded login gate ============================ */
function LoginScreen({ onAuth }){
  const [u,setU]=useState(""); const [p,setP]=useState(""); const [err,setErr]=useState(""); const [show,setShow]=useState(false);
  const USERS={ "Addem":"Addem123", "Inversiones":"Inversiones123" };
  const submit=()=>{ const name=u.trim(); if(USERS[name]!==undefined && USERS[name]===p){ setErr(""); onAuth(name); } else { setErr("Incorrect username or password."); } };
  const onKey=e=>{ if(e.key==="Enter") submit(); };
  const wrap={minHeight:"100vh",width:"100%",display:"flex",alignItems:"center",justifyContent:"center",
    background:"linear-gradient(155deg, #115a4d 0%, "+T.green800+" 45%, #082d27 100%)",
    fontFamily:"'Inter Tight', system-ui, -apple-system, sans-serif",padding:"24px",boxSizing:"border-box"};
  const card={width:"100%",maxWidth:392,background:"#ffffff",borderRadius:20,padding:"40px 34px 30px",
    boxShadow:"0 40px 90px rgba(0,0,0,.40), 0 2px 0 rgba(255,255,255,.04)",textAlign:"center",boxSizing:"border-box"};
  const logoBadge={width:74,height:74,borderRadius:18,margin:"0 auto 18px",display:"flex",alignItems:"center",
    justifyContent:"center",background:T.mint100,border:"1px solid "+T.mint200};
  const title={fontSize:23,fontWeight:700,letterSpacing:"-.01em",color:T.green800,margin:"0"};
  const sub={fontSize:12.5,letterSpacing:".14em",textTransform:"uppercase",color:T.ink400,margin:"4px 0 26px",fontWeight:600};
  const field={textAlign:"left",marginBottom:14};
  const lab={display:"block",fontSize:10.5,letterSpacing:".06em",textTransform:"uppercase",color:T.ink400,fontWeight:600,marginBottom:6};
  const inp={width:"100%",height:46,padding:"0 14px",border:"1px solid "+T.gray300,borderRadius:11,fontSize:14.5,
    fontFamily:"inherit",color:T.charcoal,outline:"none",boxSizing:"border-box",background:T.offWhite||"#F7F7F7"};
  const btn={width:"100%",height:48,marginTop:6,border:"none",borderRadius:11,background:T.green800,color:"#fff",
    fontSize:14.5,fontWeight:600,fontFamily:"inherit",cursor:"pointer",letterSpacing:".01em"};
  const errStyle={color:"#a8443a",fontSize:12.5,margin:"2px 0 12px",textAlign:"left",fontWeight:500};
  const foot={marginTop:24,fontSize:10.5,color:T.ink400,letterSpacing:".02em",lineHeight:1.5};
  return <div style={wrap}>
    <style>{CSS}</style>
    <div style={card}>
      <div style={logoBadge}><img src={ASSETS.SYMBOL_GREEN} alt="Addem Capital" style={{width:46,height:46,objectFit:"contain"}}/></div>
      <h1 style={title}>Addem Capital</h1>
      <div style={sub}>Executive Dashboard</div>
      <div style={field}>
        <label style={lab}>Username</label>
        <input style={inp} value={u} autoFocus autoComplete="username" placeholder="Username"
          onChange={e=>setU(e.target.value)} onKeyDown={onKey}/>
      </div>
      <div style={field}>
        <label style={lab}>Password</label>
        <div style={{position:"relative"}}>
          <input style={{...inp,paddingRight:46}} type={show?"text":"password"} value={p} autoComplete="current-password" placeholder="Password"
            onChange={e=>setP(e.target.value)} onKeyDown={onKey}/>
          <button type="button" onClick={()=>setShow(s=>!s)} aria-label={show?"Hide password":"Show password"}
            style={{position:"absolute",right:6,top:"50%",transform:"translateY(-50%)",height:34,width:34,display:"flex",alignItems:"center",justifyContent:"center",
              background:"none",border:"none",cursor:"pointer",color:T.ink400,padding:0}}>
            {show
              ? <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>
              : <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>}
          </button>
        </div>
      </div>
      {err && <div style={errStyle}>{err}</div>}
      <button style={btn} onClick={submit}>Sign in</button>
      <div style={foot}>Goldberg-Zogovic S.A.P.I. de C.V.<br/>SOFOM E.N.R.</div>
    </div>
  </div>;
}

export default function Root(){
  const [authed,setAuthed]=useState(()=>{ try{ return sessionStorage.getItem("addem_auth")==="1"; }catch(e){ return false; } });
  const [authUser,setAuthUser]=useState(()=>{ try{ return sessionStorage.getItem("addem_user")||""; }catch(e){ return ""; } });
  const logout=()=>{ try{ sessionStorage.removeItem("addem_auth"); sessionStorage.removeItem("addem_user"); }catch(e){} setAuthUser(""); setAuthed(false); };
  if(!authed) return <LoginScreen onAuth={(name)=>{ try{ sessionStorage.setItem("addem_auth","1"); sessionStorage.setItem("addem_user",name||""); }catch(e){} setAuthUser(name||""); setAuthed(true); }}/>;
  return <Dashboard onLogout={logout} authUser={authUser}/>;
}
